async function emp_saveHistoryToServer(entry) {
  try {
    const tenant = (typeof mt_getActiveTenant === 'function') ? mt_getActiveTenant() : null;
    if (!tenant || !tenant.id || !entry.employeeId) return;
    await fetch('/api/public/shift-history/' + encodeURIComponent(tenant.id), {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify(entry)
    }).catch(() => {});
  } catch(e) {}
}
async function emp_loadHistoryFromServer() {
  try {
    const tenant = (typeof mt_getActiveTenant === 'function') ? mt_getActiveTenant() : null;
    const uid = empState.user?.id;
    if (!tenant || !tenant.id || !uid) return;
    const resp = await fetch('/api/public/shift-history/' + encodeURIComponent(tenant.id) + '/' + uid);
    if (!resp.ok) return;
    const serverHistory = await resp.json();
    if (Array.isArray(serverHistory) && serverHistory.length > 0) {
      // Merge with local, deduplicate by timestamp
      const localTs = new Set(empState.sessionHistory.map(h => h.timestamp));
      const newEntries = serverHistory.filter(h => !localTs.has(h.timestamp));
      empState.sessionHistory = [...empState.sessionHistory, ...newEntries]
        .sort((a,b) => (b.timestamp||0) - (a.timestamp||0)).slice(0, 50);
      emp_saveHistory();
      renderPage();
    }
  } catch(e) {}
}
function emp_loadSession() {
  try {
    const raw = localStorage.getItem('fb_emp_session');
    if (!raw) return false;
    const s = verifyData(raw);
    if (!s || !validateEmpSessionShape(s)) { localStorage.removeItem('fb_emp_session'); return false; }
    empState = { ...empState, ...s };
    return true;
  } catch { return false; }
}
function emp_saveSession() {
  try {
    const data = {
      user: empState.user, active: empState.active,
      page: empState.page === 'login' ? 'readings' : empState.page,
      openReadings: empState.openReadings, closeReadings: empState.closeReadings,
      sales: empState.sales, dipReadings: empState.dipReadings,
      pendingSales: empState.pendingSales || [], // FA-01: persist queue across page refreshes
    };
    localStorage.setItem('fb_emp_session', signData(data));
  } catch {}
}
function emp_clearSession() { try { localStorage.removeItem('fb_emp_session'); } catch {} }

// ── FA-01: Offline sale queue — flush on reconnect ─────────────────────────
async function emp_flushPendingSales() {
  if (!navigator.onLine) return;
  const tenant = (typeof mt_getActiveTenant === 'function') ? mt_getActiveTenant() : null;
  if (!tenant || !tenant.id) return;
  const queue = empState.pendingSales || [];
  if (!queue.length) return;

  const toRetry = [...queue];
  empState.pendingSales = [];
  emp_saveSession();

  let savedCount = 0, failedCount = 0;
  for (const sale of toRetry) {
    try {
      const resp = await fetch('/api/public/sales/' + encodeURIComponent(tenant.id), {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(sale),
      });
      if (resp.ok) {
        // FIX 33c: server returns { duplicate: true } for idempotent retries — still a success
        savedCount++;
      }
      else { empState.pendingSales.push(sale); failedCount++; }
    } catch {
      empState.pendingSales.push(sale);
      failedCount++;
    }
  }
  emp_saveSession();
  if (savedCount > 0) {
    toast(`✅ ${savedCount} pending sale(s) synced to server`, 'success');
    renderPage();
  }
  if (failedCount > 0) {
    console.warn('[emp] ' + failedCount + ' sale(s) still pending — will retry on next reconnect');
  }
}

// Auto-flush when connectivity restores
if (typeof window !== 'undefined') {
  window.addEventListener('online', () => {
    setTimeout(emp_flushPendingSales, 800); // small delay for connection to stabilise
  });
}

