// ═══════════════════════════════════════════════════════════════
// EMPLOYEE ACTIONS
// ═══════════════════════════════════════════════════════════════

// ── WEBAUTHN BIOMETRIC LOGIN ────────────────────────────────────────────────
// Credentials stored in localStorage keyed by empId + tenantId
// No biometric data ever leaves the device — only a public key is stored

const BIO_FAIL_KEY = 'fb_bio_fails'; // { empId: count }
const BIO_MAX_FAILS = 3;

function emp_bioStorageKey(empId) {
  const tid = APP.tenant?.id || 'default';
  return `fb_bio_cred_${tid}_${empId}`;
}

function emp_bioIsRegistered(empId) {
  try {
    const raw = localStorage.getItem(emp_bioStorageKey(empId));
    return !!raw;
  } catch(e) { return false; }
}

function emp_bioGetFails(empId) {
  try {
    const d = JSON.parse(localStorage.getItem(BIO_FAIL_KEY) || '{}');
    return d[empId] || 0;
  } catch(e) { return 0; }
}

function emp_bioRecordFail(empId) {
  try {
    const d = JSON.parse(localStorage.getItem(BIO_FAIL_KEY) || '{}');
    d[empId] = (d[empId] || 0) + 1;
    localStorage.setItem(BIO_FAIL_KEY, JSON.stringify(d));
    return d[empId];
  } catch(e) { return BIO_MAX_FAILS; }
}

function emp_bioClearFails(empId) {
  try {
    const d = JSON.parse(localStorage.getItem(BIO_FAIL_KEY) || '{}');
    delete d[empId];
    localStorage.setItem(BIO_FAIL_KEY, JSON.stringify(d));
  } catch(e) {}
}

// Called from admin panel: register biometric for an employee after PIN verified
async function emp_bioRegister(empId) {
  if (!window.PublicKeyCredential) {
    toast('Biometrics not supported on this device/browser', 'error'); return false;
  }
  try {
    const available = await PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable();
    if (!available) {
      toast('No fingerprint/face sensor available', 'error'); return false;
    }

    const challenge = new Uint8Array(32);
    crypto.getRandomValues(challenge);
    const tid = APP.tenant?.id || 'default';
    const emp = EMP_LIST.find(e => e.id === empId);
    if (!emp) { toast('Employee not found', 'error'); return false; }

    const credential = await navigator.credentials.create({
      publicKey: {
        challenge,
        rp: { name: 'FuelBunk Pro', id: location.hostname },
        user: {
          id: new TextEncoder().encode(`${tid}_${empId}`),
          name: emp.name,
          displayName: emp.name,
        },
        pubKeyCredParams: [
          { alg: -7, type: 'public-key' },   // ES256
          { alg: -257, type: 'public-key' },  // RS256
        ],
        authenticatorSelection: {
          authenticatorAttachment: 'platform',
          userVerification: 'required',
          residentKey: 'preferred',
        },
        timeout: 60000,
        attestation: 'none',
      }
    });

    // Store credential ID (not biometric data — that never leaves the OS)
    const credId = btoa(String.fromCharCode(...new Uint8Array(credential.rawId)));
    localStorage.setItem(emp_bioStorageKey(empId), JSON.stringify({ credId, empId, registered: Date.now() }));
    emp_bioClearFails(empId);
    toast(`Biometric registered for ${emp.name} ✓`, 'success');
    return true;
  } catch(e) {
    if (e.name === 'NotAllowedError') toast('Biometric registration cancelled', 'info');
    else toast('Registration failed: ' + e.message, 'error');
    return false;
  }
}

async function emp_biometricLogin() {
  const id = parseInt(document.getElementById('empLoginName')?.value);
  if (!id) { toast('Select your name first', 'error'); return; }
  const emp = EMP_LIST.find(e => e.id === id);
  if (!emp) { toast('Select your name first', 'error'); return; }

  // Check fail count — force PIN if already hit 3 fails
  const fails = emp_bioGetFails(id);
  if (fails >= BIO_MAX_FAILS) {
    emp_showPinFallback(true);
    toast('Too many failed attempts — please use PIN', 'error');
    return;
  }

  if (!emp_bioIsRegistered(id)) {
    emp_showPinFallback(false);
    return;
  }

  const btn = document.getElementById('empBioBtn');
  const status = document.getElementById('empBioStatus');
  if (btn) { btn.disabled = true; btn.innerHTML = '<span style="font-size:22px">⏳</span> Verifying…'; }
  if (status) status.textContent = `Attempt ${fails + 1} of ${BIO_MAX_FAILS} — touch sensor or look at camera`;

  try {
    if (!window.PublicKeyCredential) throw new Error('WebAuthn not supported');

    const challenge = new Uint8Array(32);
    crypto.getRandomValues(challenge);

    const assertion = await navigator.credentials.get({
      publicKey: {
        challenge,
        timeout: 30000,
        userVerification: 'required',
        rpId: location.hostname,
      }
    });

    if (!assertion) throw new Error('No credential returned');

    // Biometric verified by device OS — grant access
    emp_bioClearFails(id);
    if (btn) { btn.disabled = false; btn.innerHTML = '<span style="font-size:22px">🔒</span> Login with Biometrics'; }
    if (status) status.textContent = '';

    // Complete login (same flow as PIN login, skip PIN check)
    await emp_completeLogin(emp, false);

  } catch(e) {
    if (btn) { btn.disabled = false; btn.innerHTML = '<span style="font-size:22px">🔒</span> Login with Biometrics'; }

    if (e.name === 'NotAllowedError') {
      // User cancelled or sensor failed
      const newFails = emp_bioRecordFail(id);
      const remaining = BIO_MAX_FAILS - newFails;
      if (newFails >= BIO_MAX_FAILS) {
        emp_showPinFallback(true);
        toast(`Biometric failed ${BIO_MAX_FAILS} times — enter PIN`, 'error');
      } else {
        if (status) status.textContent = `Failed ${newFails}/${BIO_MAX_FAILS} — ${remaining} attempt${remaining > 1 ? 's' : ''} left`;
        toast(`Biometric failed — ${remaining} attempt${remaining > 1 ? 's' : ''} left`, 'error');
      }
    } else {
      toast('Biometric error: ' + (e.message || e.name), 'error');
    }
  }
}

// Shared login completion — called by both biometric and PIN paths
async function emp_completeLogin(emp, isPinLogin) {
  recordSuccessLogin('emp_' + emp.id);
  APP.loggedIn = true; APP.role = 'employee'; saveSession();

  // Get JWT token
  try {
    const tenant = (typeof mt_getActiveTenant === 'function') ? mt_getActiveTenant() : null;
    if (tenant && tenant.id && isPinLogin) {
      const pin = document.getElementById('empLoginPin')?.value || '';
      const tokenResult = await AuthAPI.employeeLogin(pin, tenant.id).catch(() => null);
      if (tokenResult?.token && tokenResult?.employeeId) {
        emp = { ...emp, permissions: tokenResult.permissions || emp.permissions || {} };
      }
    }
  } catch(e) {}

  let inAppRestored = false;
  try {
    const rawS = localStorage.getItem('fb_emp_session');
    if (rawS) {
      const savedS = verifyData(rawS);
      if (savedS && savedS.user && savedS.user.id === emp.id && savedS.active) {
        empState = { ...empState, ...savedS };
        inAppRestored = true;
      }
    }
  } catch(ex) {}

  if (!inAppRestored) {
    const freshOpenings = {};
    (APP.data?.pumps || []).forEach(p => {
      const nr = p.nozzleReadings || {};
      const labels = p.nozzleLabels || (p.nozzles === 1 ? ['A'] : p.nozzles === 2 ? ['A','B'] : ['A','B','C'].slice(0, p.nozzles));
      labels.forEach(n => {
        const k = emp_key(p.id, n);
        if (nr[n] !== undefined && nr[n] > 0) freshOpenings[k] = nr[n];
      });
    });
    empState.openReadings = freshOpenings;
    empState.closeReadings = {}; empState.sales = []; empState.dipReadings = [];
    empState.page = 'readings';
  } else {
    if (!empState.page || empState.page === 'login') empState.page = 'readings';
  }
  empState.user = { id: emp.id, name: emp.name, role: emp.role, permissions: emp.permissions || {} };
  empState.active = true;

  const allAllocFuels = [];
  emp_myPumps().forEach(p => {
    (p.nozzles || []).forEach(n => {
      const ft = (p.nozzleFuels || {})[n] || p.fuelType;
      if (!allAllocFuels.includes(ft)) allAllocFuels.push(ft);
    });
  });
  if (allAllocFuels.length > 0) empSaleFuel = allAllocFuels[0];

  emp_saveSession(); auditLog('login', { employee: emp.name });
  toast((inAppRestored && empState.sales.length > 0)
    ? `Welcome back ${sanitize(emp.name)}! ${empState.sales.length} sale(s) restored.`
    : `Welcome ${sanitize(emp.name)}!`, 'success');
  renderPage();
}

async function emp_doLogin() {
  if (!Array.isArray(EMP_LIST) || EMP_LIST.length === 0) {
    toast('No employees configured for this station','error');
    return;
  }
  const id = parseInt(document.getElementById('empLoginName').value);
  const pin = (document.getElementById('empLoginPin')?.value || '').trim();
  // Use parseInt on both sides — e.id may be number or string depending on data source
  let emp = EMP_LIST.find(e => parseInt(e.id) === id);
  // Fallback: search fb_emp_cache directly in case EMP_LIST is out of sync
  if (!emp) {
    try {
      const cached = JSON.parse(localStorage.getItem('fb_emp_cache') || '[]');
      const hit = cached.find(e => parseInt(e.id) === id);
      if (hit) emp = { id: hit.id, name: hit.name, role: hit.role,
                       shift: hit.shift||'', permissions: hit.permissions||{}, pinHash: hit.pinHash||null };
    } catch(e) {}
  }
  if (!emp) { toast('Select employee','error'); return; }
  if (!checkRateLimit('emp_' + id)) return;
  const pinHash = await hashPassword(pin);
  // IR-01 FIX: Verify PIN server-side (hashes no longer served publicly).
  // Falls back to locally cached hash (stored in IDB during admin loadData) when offline.
  let pinValid = false;
  try {
    const tenant = (typeof mt_getActiveTenant === 'function') ? mt_getActiveTenant() : null;
    if (tenant && tenant.id && navigator.onLine) {
      const verifyResp = await fetch('/api/public/verify-pin/' + encodeURIComponent(tenant.id), {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ employeeId: id, pinHash }),
      });
      if (verifyResp.ok) {
        const result = await verifyResp.json();
        pinValid = result.valid === true;
      } else {
        // Server error — fall back to cached hash (only if real hash, not sentinel)
        pinValid = (emp.pinHash && emp.pinHash !== '__server__') ? pinHash === emp.pinHash : false;
      }
    } else {
      // Offline — use locally cached hash (populated from IDB during app init)
      pinValid = (emp.pinHash && emp.pinHash !== '__server__') ? pinHash === emp.pinHash : false;
    }
  } catch {
    // Network failure — offline fallback
    pinValid = (emp.pinHash && emp.pinHash !== '__server__') ? pinHash === emp.pinHash : false;
  }
  if (!pinValid) { recordFailedLogin('emp_' + id); toast('Incorrect PIN','error'); return; }
  // PIN success — clear bio fail counter so they get fresh 3 attempts next time
  emp_bioClearFails(id);
  recordSuccessLogin('emp_' + id);

  // Restore existing session if same employee re-logging in during same shift
  let inAppRestored = false;
  try {
    const rawS = localStorage.getItem('fb_emp_session');
    if (rawS) {
      const savedS = verifyData(rawS);
      if (savedS && savedS.user && savedS.user.id === emp.id && savedS.active) {
        empState = { ...empState, ...savedS };
        inAppRestored = true;
      }
    }
  } catch(ex) {}

  if (!inAppRestored) {
    // Pre-fill opening readings from last stored nozzle readings (last close = this open)
    // Use APP.data.pumps directly — emp_myPumps/getEmpPumps strip nozzleReadings
    const freshOpenings = {};
    (APP.data?.pumps || []).forEach(p => {
      const nr = p.nozzleReadings || {};
      const labels = p.nozzleLabels || (p.nozzles === 1 ? ['A'] : p.nozzles === 2 ? ['A','B'] : ['A','B','C'].slice(0, p.nozzles));
      labels.forEach(n => {
        const k = emp_key(p.id, n);
        if (nr[n] !== undefined && nr[n] > 0) freshOpenings[k] = nr[n];
      });
    });
    empState.openReadings = freshOpenings;
    empState.closeReadings = {}; empState.sales = []; empState.dipReadings = [];
    empState.page = 'readings';
  } else {
    if (!empState.page || empState.page === 'login') empState.page = 'readings';
  }
  empState.user = { id: emp.id, name: emp.name, role: emp.role, permissions: emp.permissions || {} };
  empState.active = true;

  // Set default fuel to first fuel in employee's assigned nozzles
  const allAllocFuels = [];
  emp_myPumps().forEach(p => {
    (p.nozzles || []).forEach(n => {
      const ft = (p.nozzleFuels || {})[n] || p.fuelType;
      if (!allAllocFuels.includes(ft)) allAllocFuels.push(ft);
    });
  });
  if (allAllocFuels.length > 0) empSaleFuel = allAllocFuels[0];

  emp_saveSession(); auditLog('login', { employee: emp.name });
  if (inAppRestored && empState.sales.length > 0) {
    toast('Welcome back ' + sanitize(emp.name) + '! ' + empState.sales.length + ' sale(s) restored.', 'success');
  } else {
    toast('Welcome ' + sanitize(emp.name) + '!', 'success');
  }
  emp_go('readings');
}

function emp_saveReading(mode, key, value) {
  const v = parseFloat(value);
  if (isNaN(v) || v < 0) { if (mode==='open') delete empState.openReadings[key]; else delete empState.closeReadings[key]; }
  else {
    if (v > 9999999) { toast('Reading value too large', 'error'); return; }
    if (mode === 'open') empState.openReadings[key] = v;
    else {
      const ov = empState.openReadings[key];
      if (ov !== undefined && v < ov) { toast('Closing must be ≥ opening','error'); return; }
      if (ov !== undefined && (v - ov) > 10000) { toast('Difference exceeds 10,000L. Verify reading.','error'); return; }
      empState.closeReadings[key] = v;
    }
  }
  emp_saveSession();
  const c = document.getElementById('empReadCards');
  if (c) c.innerHTML = emp_renderCards(mode);
}

function emp_switchMode(mode) {
  const c = document.getElementById('empReadCards');
  if (c) c.innerHTML = emp_renderCards(mode);
  // Update tab button states without full re-render
  document.querySelectorAll('.emp-mode-tab').forEach(btn => {
    btn.classList.toggle('btn-accent', btn.dataset.mode === mode);
    btn.classList.toggle('btn-ghost', btn.dataset.mode !== mode);
  });
}

function emp_refreshNozzles() {
  // Rebuild combined pump+nozzle button row for the current fuel
  const wrap = document.getElementById('empPumpNozzleBtns');
  if (!wrap) return;
  const pumps = emp_myPumps().filter(p => {
    const nf = p.nozzleFuels || {};
    return p.fuelType === empSaleFuel || Object.values(nf).includes(empSaleFuel);
  });
  if (!pumps.length) { wrap.innerHTML = '<span style="font-size:12px;color:var(--text-3)">No pump for this fuel</span>'; return; }
  let firstSet = true;
  wrap.innerHTML = pumps.map(pump => {
    const nf = pump.nozzleFuels || {};
    const nozzles = (pump.nozzles || []).filter(n => (nf[n] || pump.fuelType) === empSaleFuel);
    if (!nozzles.length) return '';
    const pumpActive = firstSet; firstSet = false;
    return nozzles.map((n, ni) => {
      const active = pumpActive && ni === 0;
      return `<button class="btn btn-sm ${active?'btn-accent':'btn-ghost'}" data-pumpbtn="${pump.id}" data-nozzlebtn="${n}" onclick="emp_selPumpNozzle('${pump.id}','${n}')" style="display:flex;flex-direction:column;align-items:center;padding:8px 14px;min-width:72px"><span style="font-size:13px;font-weight:800">${pump.name}</span><span style="font-size:10px;opacity:0.8;margin-top:1px">Nozzle ${n}</span></button>`;
    }).join('');
  }).join('');
}

function emp_selFuel(f) {
  empSaleFuel = f;
  // Update fuel button highlights without full renderPage (preserves form inputs)
  document.querySelectorAll('[data-fuelbtn]').forEach(btn => {
    btn.classList.toggle('btn-accent', btn.dataset.fuelbtn === f);
    btn.classList.toggle('btn-ghost', btn.dataset.fuelbtn !== f);
  });
  // Rebuild combined pump+nozzle buttons for new fuel
  emp_refreshNozzles();
  emp_calcAmt();
  // Update price display if visible
  const priceEl = document.getElementById('empFuelPrice');
  if (priceEl) priceEl.textContent = cur(EMP_PRICES[f] || 0) + '/L';
}
function emp_selPumpNozzle(pumpId, nozzle) {
  document.querySelectorAll('[data-pumpbtn]').forEach(btn => {
    const match = String(btn.dataset.pumpbtn) === String(pumpId) && btn.dataset.nozzlebtn === nozzle;
    btn.classList.toggle('btn-accent', match);
    btn.classList.toggle('btn-ghost',  !match);
  });
}
// Keep legacy shims so any other callers don't crash
function emp_selPump(pumpId) {
  const first = document.querySelector(`[data-pumpbtn="${pumpId}"]`);
  if (first) emp_selPumpNozzle(pumpId, first.dataset.nozzlebtn);
}
function emp_selNozzle(n) {
  const first = document.querySelector(`[data-nozzlebtn="${n}"]`);
  if (first) emp_selPumpNozzle(first.dataset.pumpbtn, n);
}
function emp_selPay(m) {
  empPayMode = m;
  // Update payment button highlights
  document.querySelectorAll('[data-paybtn]').forEach(btn => {
    btn.classList.toggle('btn-accent', btn.dataset.paybtn === m);
    btn.classList.toggle('btn-ghost', btn.dataset.paybtn !== m);
  });
  // Show/hide credit customer field without full re-render
  const custWrap = document.getElementById('empCustWrap');
  if (custWrap) custWrap.style.display = m === 'credit' ? '' : 'none';
}
function emp_calcAmt() {
  const price = EMP_PRICES[empSaleFuel] || 0;
  const litersEl = document.getElementById('empSaleLiters');
  const amtEl = document.getElementById('empSaleAmt');
  if (!litersEl || !amtEl) return;
  const l = parseFloat(litersEl.value) || 0;
  if (l > 0 && price > 0) {
    amtEl.dataset.manualAmt = '';
    amtEl.value = (l * price).toFixed(2);
  }
}
function emp_calcLiters() {
  const price = EMP_PRICES[empSaleFuel] || 0;
  const litersEl = document.getElementById('empSaleLiters');
  const amtEl = document.getElementById('empSaleAmt');
  if (!litersEl || !amtEl || price <= 0) return;
  const a = parseFloat(amtEl.value) || 0;
  if (a > 0) { amtEl.dataset.manualAmt = '1'; litersEl.value = (a / price).toFixed(2); }
  else amtEl.dataset.manualAmt = '';
}

// ── VEHICLE — SEGMENTED INPUT ──────────────────────────────────────────────

function emp_vehGetPlate() {
  const state  = (document.getElementById('veh_state')?.value  || '').toUpperCase().replace(/[^A-Z]/g, '');
  const dist   = (document.getElementById('veh_dist')?.value   || '').replace(/[^0-9]/g, '');
  const series = (document.getElementById('veh_series')?.value || '').toUpperCase().replace(/[^A-Z]/g, '');
  const num    = (document.getElementById('veh_num')?.value    || '').replace(/[^0-9]/g, '');
  return state + dist + series + num;
}

function emp_vehSetPlate(plate) {
  plate = (plate || '').toUpperCase().replace(/[^A-Z0-9]/g, '');
  const m = plate.match(/^([A-Z]{2})(\d{2})([A-Z]{0,3})(\d{1,4})$/);
  const s  = document.getElementById('veh_state');
  const d  = document.getElementById('veh_dist');
  const sr = document.getElementById('veh_series');
  const n  = document.getElementById('veh_num');
  if (m) {
    if (s)  s.value  = m[1];
    if (d)  d.value  = m[2];
    if (sr) sr.value = m[3];
    if (n)  n.value  = m[4];
    if (n) n.focus();
  } else if (plate.length >= 2) {
    if (s)  s.value  = plate.slice(0,2);
    if (d)  d.value  = plate.slice(2,4).replace(/[^0-9]/g,'');
    if (sr) sr.value = plate.slice(4,7).replace(/[^A-Z]/g,'');
    if (n)  n.value  = plate.slice(-4).replace(/[^0-9]/g,'');
    if (n) n.focus();
  }
  document.querySelectorAll('.veh-seg').forEach(el => {
    el.style.borderColor = 'var(--green)';
    setTimeout(() => { el.style.borderColor = ''; }, 800);
  });
}

function emp_vehSegInput(el, nextId, prevId, maxLen, type) {
  let v = el.value.toUpperCase();
  if (type === 'num') v = v.replace(/[^0-9]/g, '');
  else v = v.replace(/[^A-Z0-9]/g, '');
  el.value = v;
  if (v.length >= maxLen && nextId) {
    setTimeout(() => document.getElementById(nextId)?.focus(), 0);
  }
}

function emp_vehSegKey(e, prevId, nextId) {
  const el = e.target;
  if (e.key === 'Backspace' && el.value === '' && prevId) {
    e.preventDefault();
    const prev = document.getElementById(prevId);
    if (prev) { prev.focus(); prev.setSelectionRange(prev.value.length, prev.value.length); }
  }
  if (e.key === 'ArrowRight' && el.selectionStart === el.value.length && nextId) {
    document.getElementById(nextId)?.focus();
  }
  if (e.key === 'ArrowLeft' && el.selectionStart === 0 && prevId) {
    const prev = document.getElementById(prevId);
    if (prev) { prev.focus(); prev.setSelectionRange(prev.value.length, prev.value.length); }
  }
}

function emp_pickVeh(v) { emp_vehSetPlate(v); }
function emp_vehHide() {}

// ── CAMERA OCR ──────────────────────────────────────────────────────────────
function emp_vehCamera() {
  document.getElementById('vehCamInput')?.click();
}

async function emp_vehProcessImage(input) {
  const file = input?.files?.[0];
  if (!file) return;
  input.value = '';
  const btn = document.getElementById('vehCamBtn');
  const hint = document.getElementById('vehHint');
  if (btn) btn.textContent = '⏳';
  if (hint) hint.textContent = 'Reading plate…';

  const img = new Image();
  img.onload = async () => {
    let plateText = null;

    // 1) Native TextDetector — Chrome Android, no deps, fast
    if ('TextDetector' in window) {
      try {
        const det = new window.TextDetector();
        const results = await det.detect(img);
        for (const r of results) {
          const t = r.rawValue.replace(/[^A-Z0-9]/gi, '').toUpperCase();
          if (/^[A-Z]{2}\d{2}[A-Z]{0,3}\d{4}$/.test(t)) { plateText = t; break; }
        }
        if (!plateText) {
          for (const r of results) {
            const t = r.rawValue.replace(/[^A-Z0-9]/gi, '').toUpperCase();
            if (t.length >= 6 && t.length <= 12) { plateText = t; break; }
          }
        }
      } catch(e) {}
    }

    // 2) Tesseract.js — truly lazy: loaded only on first camera tap (6MB, 0 cost otherwise)
    if (!plateText) {
      try {
        if (!window.Tesseract) {
          // dynamic import() — browser fetches 6MB only when this line executes
          await new Promise((res, rej) => {
            const s = document.createElement('script');
            s.src = 'https://cdn.jsdelivr.net/npm/tesseract.js@5/dist/tesseract.min.js';
            s.onload = res;
            s.onerror = () => rej(new Error('Tesseract load failed'));
            document.head.appendChild(s);
          });
        }
        if (window.Tesseract) {
          const canvas = document.createElement('canvas');
          canvas.width = img.naturalWidth; canvas.height = img.naturalHeight;
          const ctx = canvas.getContext('2d');
          ctx.drawImage(img, 0, 0);
          // Greyscale + threshold for better plate contrast
          const id = ctx.getImageData(0, 0, canvas.width, canvas.height);
          for (let i = 0; i < id.data.length; i += 4) {
            const avg = 0.299*id.data[i] + 0.587*id.data[i+1] + 0.114*id.data[i+2];
            const v = avg > 120 ? 255 : 0;
            id.data[i] = id.data[i+1] = id.data[i+2] = v;
          }
          ctx.putImageData(id, 0, 0);
          const worker = await Tesseract.createWorker('eng', 1, { logger: () => {} });
          await worker.setParameters({
            tessedit_char_whitelist: 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789',
            tessedit_pageseg_mode: '7'
          });
          const { data: { text } } = await worker.recognize(canvas);
          await worker.terminate();
          const raw = text.replace(/[^A-Z0-9]/gi, '').toUpperCase().trim();
          if (raw.length >= 5) plateText = raw;
        }
      } catch(e) { console.warn('[OCR] Tesseract failed:', e.message); }
    }

    if (btn) btn.textContent = '📷';
    if (hint) hint.textContent = 'Type each part · 📷 point at plate · 🎤 say the plate number';
    URL.revokeObjectURL(img.src);

    if (plateText) {
      emp_vehSetPlate(plateText);
      toast('Plate read: ' + plateText, 'success');
    } else {
      toast('Could not read plate — type manually', 'info');
    }
  };
  img.onerror = () => { if (btn) btn.textContent = '📷'; toast('Image error', 'error'); };
  img.src = URL.createObjectURL(file);
}

// ── VOICE INPUT ──────────────────────────────────────────────────────────────
let _vehRecognition = null;
function emp_vehVoice() {
  const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
  if (!SR) { toast('Voice not supported — try Chrome', 'error'); return; }
  const btn = document.getElementById('vehMicBtn');

  if (_vehRecognition) {
    _vehRecognition.stop(); _vehRecognition = null;
    if (btn) { btn.textContent = '🎤'; btn.style.background = ''; }
    return;
  }

  _vehRecognition = new SR();
  _vehRecognition.lang = 'en-IN';
  _vehRecognition.continuous = false;
  _vehRecognition.interimResults = false;
  _vehRecognition.maxAlternatives = 5;

  _vehRecognition.onstart = () => {
    if (btn) { btn.textContent = '🔴'; btn.style.background = 'var(--red-dim)'; }
    const hint = document.getElementById('vehHint');
    if (hint) hint.textContent = '🎤 Listening… say e.g. "KA zero six P six six seven two"';
    toast('Listening…', 'info');
  };

  _vehRecognition.onresult = (e) => {
    let bestPlate = null;
    for (let i = 0; i < e.results[0].length; i++) {
      const t = e.results[0][i].transcript;
      const p = emp_vehParseSpeech(t);
      if (p && (!bestPlate || p.length > bestPlate.length)) bestPlate = p;
    }
    const hint = document.getElementById('vehHint');
    if (hint) hint.textContent = 'Type each part · 📷 point at plate · 🎤 say the plate number';
    const raw = e.results[0][0].transcript;
    if (bestPlate) {
      emp_vehSetPlate(bestPlate);
      toast('Got: ' + bestPlate, 'success');
    } else {
      const r2 = raw.replace(/[^A-Z0-9]/gi,'').toUpperCase();
      if (r2) emp_vehSetPlate(r2);
      toast('Heard: "' + raw + '" — correct if needed', 'info');
    }
  };

  _vehRecognition.onerror = (e) => {
    if (e.error !== 'no-speech') toast('Voice error: ' + e.error, 'error');
  };

  _vehRecognition.onend = () => {
    _vehRecognition = null;
    if (btn) { btn.textContent = '🎤'; btn.style.background = ''; }
  };

  _vehRecognition.start();
}

function emp_vehParseSpeech(text) {
  text = text.toUpperCase().trim();
  const direct = text.replace(/[^A-Z0-9]/g, '');
  if (/^[A-Z]{2}\d{2}[A-Z]{0,3}\d{4}$/.test(direct)) return direct;
  const map = {
    'ZERO':'0','ONE':'1','TWO':'2','THREE':'3','FOUR':'4',
    'FIVE':'5','SIX':'6','SEVEN':'7','EIGHT':'8','NINE':'9',
    '\\bOH\\b':'0','\\bAYE\\b':'A','\\bBEE\\b':'B','\\bSEE\\b':'C',
    '\\bDEE\\b':'D','\\bEFF\\b':'F','\\bGEE\\b':'G','\\bJAY\\b':'J',
    '\\bKAY\\b':'K','\\bELL\\b':'L','\\bEMM\\b':'M','\\bEN\\b':'N',
    '\\bPEE\\b':'P','\\bCUE\\b':'Q','\\bARE\\b':'R','\\bESS\\b':'S',
    '\\bTEE\\b':'T','\\bVEE\\b':'V','\\bEX\\b':'X','\\bWHY\\b':'Y',
    '\\bZED\\b':'Z',
  };
  let r = text;
  Object.entries(map).forEach(([w, c]) => { r = r.replace(new RegExp(w, 'g'), c); });
  r = r.replace(/[^A-Z0-9]/g, '');
  if (/^[A-Z]{2}\d{2}[A-Z]{0,3}\d{4}$/.test(r)) return r;
  if (r.length >= 6) return r;
  return null;
}

function emp_recordSale() {
  const l = parseFloat(document.getElementById('empSaleLiters')?.value);
  const a = parseFloat(document.getElementById('empSaleAmt')?.value);
  const v = emp_vehGetPlate();
  const _activeBtn = document.querySelector('[data-pumpbtn].btn-accent');
  const p = String(_activeBtn?.dataset?.pumpbtn || '');  // pump.id from active combined button
  if (isNaN(l)||l<=0) { toast('Enter valid liters','error'); return; }
  // No upper liter limit
  // Vehicle required for non-cash payments; optional for cash walk-ins
  if (empPayMode !== 'cash') {
    if (!v || v.length < 2) { toast('Enter valid vehicle number','error'); return; }
  }
  if (v && v.length > 0 && !/^[A-Z0-9\s\-\.]+$/i.test(v)) { toast('Vehicle number has invalid characters','error'); return; }
  const amt = isNaN(a) || a <= 0 ? l * (EMP_PRICES[empSaleFuel] || 0) : a;
  if (isNaN(amt) || amt <= 0) { toast('Invalid amount','error'); return; }

  const nozzle = _activeBtn?.dataset?.nozzlebtn || 'A';  // nozzle from same active combined button

  const customerEl = document.getElementById('empSaleCustomer');
  const customer = customerEl ? customerEl.value.trim() : '';
  if (empPayMode === 'credit' && !customer) { toast('Select a credit customer', 'error'); return; }
  // ── Credit limit enforcement ──
  if (empPayMode === 'credit' && customer) {
    const creditCust = (APP.data?.creditCustomers || []).find(c => c.name === customer);
    if (creditCust) {
      const used = creditCust.outstanding || 0;
      const limit = creditCust.limit || creditCust.credit_limit || 0;
      if (limit > 0 && (used + amt) > limit) {
        toast(`Credit limit exceeded! Used: ${cur(used)} / Limit: ${cur(limit)}`, 'error');
        return;
      }
    }
  }

  const sale = {
    id: Date.now(), date: emp_today(), time: emp_time(),
    // FIX 33: idempotency key lets server deduplicate retries (network drop after server
    // accepted the sale but before client got the 200 response back — previously caused
    // duplicate sales when flushOfflineQueue retried). crypto.randomUUID is available in
    // all modern browsers; fallback uses timestamp + random for older contexts.
    idempotencyKey: (typeof crypto !== 'undefined' && crypto.randomUUID)
      ? crypto.randomUUID()
      : (Date.now().toString(36) + '-' + Math.random().toString(36).slice(2)),
    fuelType: empSaleFuel, liters: l, amount: amt,
    mode: empPayMode, pump: p, nozzle,
    vehicle: sanitize(v),
    customer: customer ? sanitize(customer) : undefined,
    shift: empState.shift || 'Employee',
    employee: empState.user?.name || 'Employee',
    employeeId: empState.user?.id || 0,
    employeeName: empState.user?.name || 'Employee',
  };

  // ── Save to employee session (for shift summary & reconciliation) ──
  empState.sales.unshift(sale);
  emp_saveSession();

  // ── Save to admin APP.data.sales + server DB via public endpoint ──
  if (APP.data?.sales) APP.data.sales.unshift(sale);
  // FA-01 FIX: Queue sale if network fails — emp_flushPendingSales retries on reconnect
  try {
    const tenant = (typeof mt_getActiveTenant === 'function') ? mt_getActiveTenant() : null;
    if (tenant && tenant.id) {
      fetch('/api/public/sales/' + encodeURIComponent(tenant.id), {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(sale)
      }).then(resp => {
        if (!resp.ok) {
          // HTTP error (422 credit limit, 500, etc.) — queue for retry or handle specifically
          resp.json().then(err => {
            if (resp.status === 409 && err.error && err.error.includes('inactive')) {
              // TC-018: pump is inactive — remove sale from local state, show clear error
              empState.sales = empState.sales.filter(s => s.id !== sale.id);
              if (APP.data?.sales) APP.data.sales = APP.data.sales.filter(s => s.id !== sale.id);
              toast(`❌ Pump is inactive — sale rejected. Contact admin.`, 'error');
              emp_saveSession();
              renderPage();
            } else if (resp.status === 422 && (err.error === 'Credit limit exceeded' || err.error === 'credit_limit_exceeded')) {
              // FIX F-10: server hard-blocks credit sales that exceed limit — remove from local state
              empState.sales = empState.sales.filter(s => s.id !== sale.id);
              if (APP.data?.sales) APP.data.sales = APP.data.sales.filter(s => s.id !== sale.id);
              const remaining = err.remainingCredit != null ? cur(err.remainingCredit) : cur(err.available || 0);
              toast(`❌ Credit limit exceeded. Available credit: ${remaining}. Ask customer to make a payment first.`, 'error');
              // Also reverse the local outstanding balance update
              if (empPayMode === 'credit' && sale.customer) {
                const creditCust = APP.data?.creditCustomers?.find(c => c.name === sale.customer);
                if (creditCust) creditCust.outstanding = Math.max(0, (creditCust.outstanding || 0) - sale.amount);
              }
              emp_saveSession();
              renderPage();
            } else {
              console.warn('[emp sale] Server error, queuing for retry:', err.error||resp.status);
              if (!empState.pendingSales) empState.pendingSales = [];
              empState.pendingSales.unshift(sale);
              emp_saveSession();
            }
          }).catch(() => {
            if (!empState.pendingSales) empState.pendingSales = [];
            empState.pendingSales.unshift(sale);
            emp_saveSession();
          });
        }
      }).catch(err => {
        // Network failure — queue for retry when online
        console.warn('[emp sale] Network error, queuing:', err.message);
        if (!empState.pendingSales) empState.pendingSales = [];
        empState.pendingSales.unshift(sale);
        emp_saveSession();
        // Show pending badge in UI
        const pending = (empState.pendingSales || []).length;
        if (pending === 1) toast(`⚠️ Network error — sale queued, will sync when online`, 'warning');
      });
    } else {
      // Fallback: try authenticated route (same device as admin)
      db.add('sales', sale).catch(() => {});
    }
  } catch(e) {
    db.add('sales', sale).catch(() => {});
  }

  // ── If credit sale, update customer outstanding balance locally ──
  if (empPayMode === 'credit' && sale.customer) {
    const creditCust = APP.data?.creditCustomers?.find(c => c.name === sale.customer);
    if (creditCust) {
      creditCust.outstanding = (creditCust.outstanding || 0) + sale.amount;
      // Server update happens via /api/public/sales endpoint (already included above)
      // Auth update as fallback if admin is on same device
      db.put('creditCustomers', creditCust).catch(() => {});
    }
  }

  // ── NO tank deduction here — meter reading at shift end handles inventory sync
  //    to prevent double-deduction (sale + meter reading both deducting from tank)

  // ── Loyalty: earn points on credit sale (only if owner-enrolled) ────────────
  if (empPayMode === 'credit' && sale.customer) {
    const loyaltyEarnRate = APP.data?.loyaltyEarnRate || 1;
    const earnedPts = Math.floor((sale.amount / 100) * loyaltyEarnRate);
    if (earnedPts > 0) {
      const loyaltyCust = APP.data?.creditCustomers?.find(c => c.name === sale.customer);
      if (loyaltyCust && loyaltyCust.loyaltyEnrolled) {
        loyaltyCust.loyaltyPoints = (loyaltyCust.loyaltyPoints || 0) + earnedPts;
        if (!loyaltyCust.loyaltyHistory) loyaltyCust.loyaltyHistory = [];
        loyaltyCust.loyaltyHistory.unshift({ type:'earn', pts: earnedPts, balance: loyaltyCust.loyaltyPoints, ref: sale.id, date: emp_today() });
        db.put('creditCustomers', loyaltyCust).catch(() => {});
        toast('⭐ +' + earnedPts + ' loyalty pts for ' + sanitize(sale.customer) + ' (total: ' + loyaltyCust.loyaltyPoints + ')', 'info');
      }
    }
  }

  auditLog('sale_add', { ...sale, source: 'employee_portal' });
  toast(`✅ Sale recorded: ${fmt(l)}L · ${cur(amt)}`, 'success');

  // Clear inputs
  const litersEl = document.getElementById('empSaleLiters');
  const amtEl    = document.getElementById('empSaleAmt');
  const vehEl    = document.getElementById('empSaleVeh');
  if (litersEl) litersEl.value = '';
  if (amtEl)    { amtEl.value = ''; amtEl.dataset.manualAmt = ''; }
  if (vehEl)    vehEl.value    = '';
  const custEl = document.getElementById('empSaleCustomer');
  if (custEl) custEl.value = '';

  emp_go('sales');
}

// ── LOYALTY: Show balance badge when credit customer is selected at POS ──────
function emp_showLoyaltyBadge(customerName) {
  const badge = document.getElementById('empLoyaltyBadge');
  if (!badge) return;
  if (!customerName) { badge.style.display = 'none'; return; }
  const c = (APP.data?.creditCustomers||[]).find(x => x.name === customerName);
  if (!c || !c.loyaltyEnrolled) { badge.style.display = 'none'; return; }
  const pts = c.loyaltyPoints || 0;
  const redeemRate = APP.data?.loyaltyRedeemRate || 50;
  const val = Math.floor(pts / 100) * redeemRate;
  const earnRate = APP.data?.loyaltyEarnRate || 1;
  document.getElementById('empLoyaltyPts').textContent = pts.toLocaleString('en-IN');
  document.getElementById('empLoyaltyVal').textContent = '₹' + val.toFixed(0);
  document.getElementById('empLoyaltyEarn').textContent = 'Earns ' + earnRate + ' pt per ₹100 spent';
  badge.style.display = 'flex';
}
window.emp_showLoyaltyBadge = emp_showLoyaltyBadge;

// ══════════════════════════════════════════════════════════════════════════════
// ── VOICE ENTRY — Optional, degrades gracefully if browser lacks Speech API ──
// ══════════════════════════════════════════════════════════════════════════════
// Supported commands (case-insensitive):
//   "petrol 500 rupees"   → fuel=petrol, amount=500
//   "diesel 20 litres"    → fuel=diesel, liters=20
//   "premium 30 liters"   → fuel=premium_petrol, liters=30
//   "cash petrol 400"     → mode=cash, fuel=petrol, amount=400
//   "upi diesel 15 litres"
// After parsing, fields are filled; user reviews and taps 💾 Record Sale.

(function initVoiceEntry() {
  const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
  if (!SR) return; // Browser doesn't support — button stays hidden
  // Show the voice button once we confirm support
  document.addEventListener('DOMContentLoaded', () => {
    const w = document.getElementById('empVoiceWrap');
    if (w) w.style.display = 'block';
  });
  // Also expose for renderPage re-renders
  window._voiceSupported = true;
})();

function emp_initVoiceButton() {
  if (!window._voiceSupported) return;
  const w = document.getElementById('empVoiceWrap');
  if (w) w.style.display = 'block';
}
window.emp_initVoiceButton = emp_initVoiceButton;

let _voiceRecognizer = null;
let _voiceActive     = false;

function emp_voiceEntry() {
  const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
  if (!SR) {
    toast('Voice entry not supported in this browser. Try Chrome or Edge.', 'error');
    return;
  }

  if (_voiceActive && _voiceRecognizer) {
    _voiceRecognizer.stop();
    return;
  }

  const btn   = document.getElementById('empVoiceBtn');
  const label = document.getElementById('empVoiceBtnLabel');
  const status = document.getElementById('empVoiceStatus');

  _voiceRecognizer = new SR();
  _voiceRecognizer.lang = 'en-IN';
  _voiceRecognizer.interimResults = false;
  _voiceRecognizer.maxAlternatives = 3;

  _voiceRecognizer.onstart = () => {
    _voiceActive = true;
    if (btn)    btn.style.borderColor = 'rgba(239,68,68,0.6)';
    if (btn)    btn.style.color       = 'var(--red)';
    if (label)  label.textContent     = 'Listening… (tap to stop)';
    if (status) status.textContent    = '🎙️ Speak now…';
  };

  _voiceRecognizer.onresult = (event) => {
    // Try all alternatives until one parses
    let parsed = null;
    for (let i = 0; i < event.results[0].length; i++) {
      const transcript = event.results[0][i].transcript.toLowerCase().trim();
      if (status) status.textContent = '💬 Heard: "' + transcript + '"';
      parsed = emp_parseVoiceCommand(transcript);
      if (parsed) break;
    }
    if (parsed) {
      emp_applyVoiceParsed(parsed);
    } else {
      const raw = event.results[0][0].transcript;
      if (status) status.textContent = '❓ Could not parse: "' + raw + '" — try "petrol Rs 500" or "diesel 20 litres"';
      toast('Could not parse: "' + raw + '" — try "petrol Rs 500" or "diesel 20 litres"', 'warning');
    }
  };

  _voiceRecognizer.onerror = (e) => {
    const msgs = { 'no-speech':'No speech detected — try again.', 'network':'Network error — check connection.', 'not-allowed':'Microphone permission denied.' };
    if (status) status.textContent = msgs[e.error] || ('Error: ' + e.error);
    emp_voiceReset();
  };

  _voiceRecognizer.onend = () => {
    emp_voiceReset();
  };

  _voiceRecognizer.start();
}
window.emp_voiceEntry = emp_voiceEntry;

function emp_voiceReset() {
  _voiceActive     = false;
  _voiceRecognizer = null;
  const btn    = document.getElementById('empVoiceBtn');
  const label  = document.getElementById('empVoiceBtnLabel');
  if (btn)   { btn.style.borderColor = ''; btn.style.color = ''; }
  if (label) label.textContent = 'Voice Entry';
}

function emp_parseVoiceCommand(text) {
  // Normalise spoken numbers: "five hundred" → 500, "twenty" → 20
  const numWords = {
    zero:0,one:1,two:2,three:3,four:4,five:5,six:6,seven:7,eight:8,nine:9,
    ten:10,eleven:11,twelve:12,thirteen:13,fourteen:14,fifteen:15,
    sixteen:16,seventeen:17,eighteen:18,nineteen:19,twenty:20,
    thirty:30,forty:40,fifty:50,sixty:60,seventy:70,eighty:80,ninety:90,
    hundred:100,thousand:1000
  };
  let normalized = text;
  Object.entries(numWords).forEach(([w, v]) => {
    normalized = normalized.replace(new RegExp('\b' + w + '\b', 'g'), ' ' + v + ' ');
  });
  // Collapse "5 100" → 500, "2 1000" → 2000 patterns
  normalized = normalized.replace(/(\d+)\s+100/g, (m,a) => parseInt(a)*100);
  normalized = normalized.replace(/(\d+)\s+1000/g, (m,a) => parseInt(a)*1000);
  normalized = normalized.replace(/\s+/g, ' ').trim();

  const result = { fuel: null, amount: null, liters: null, mode: null };

  // Payment mode
  if (/cash/.test(normalized))   result.mode = 'cash';
  if (/upi|gpay|paytm|phone\s*pe/.test(normalized)) result.mode = 'upi';
  if (/card|swipe/.test(normalized))  result.mode = 'card';
  if (/credit/.test(normalized)) result.mode = 'credit';

  // Fuel type
  if (/petrol|pms/.test(normalized))               result.fuel = 'petrol';
  if (/diesel|hsd/.test(normalized))                result.fuel = 'diesel';
  if (/premium|speed|power/.test(normalized))   result.fuel = 'premium_petrol';

  // Amount (rupees)
  // Amount — handles "Rs 500", "petrol Rs 500", "500 rupees", "500 rs", plain "500"
  const amtPre   = normalized.match(/(?:rs|rupe(?:e)?|\u20b9|inr)\.?\s*(\d+(?:\.\d+)?)/i);
  const amtSuf   = normalized.match(/(\d+(?:\.\d+)?)\s*(?:rupe(?:e)?|\u20b9|inr)s?/i);
  const amtPlain = normalized.match(/(\d+(?:\.\d+)?)/);
  // Litres
  const litMatch = normalized.match(/(\d+(?:\.\d+)?)\s*(?:liter|litre|liters|litres|lit(?:\b|$)|l(?:\b|$))/i);
  if (litMatch)       result.liters = parseFloat(litMatch[1]);
  if (!result.liters) {
    if (amtPre)       result.amount = parseFloat(amtPre[1]);
    else if (amtSuf)  result.amount = parseFloat(amtSuf[1]);
    else if (amtPlain) result.amount = parseFloat(amtPlain[1]);
  }
  // Must have at least fuel type and one of amount/liters
  if (!result.fuel) return null;
  if (!result.amount && !result.liters) return null;
  return result;
}

function emp_applyVoiceParsed(p) {
  const status = document.getElementById('empVoiceStatus');

  // Set fuel type
  if (p.fuel) {
    // Click the matching fuel button
    document.querySelectorAll('[data-fuelbtn]').forEach(btn => {
      if (btn.dataset.fuelbtn === p.fuel) btn.click();
    });
    // Fallback: set global
    if (typeof empSaleFuel !== 'undefined') empSaleFuel = p.fuel;
  }

  // Set payment mode
  if (p.mode) {
    document.querySelectorAll('[data-paybtn]').forEach(btn => {
      if (btn.dataset.paybtn === p.mode) btn.click();
    });
  }

  // Set amount or litres
  const amtEl   = document.getElementById('empSaleAmt');
  const litEl   = document.getElementById('empSaleLiters');

  if (p.liters && litEl) {
    litEl.value = p.liters;
    litEl.dispatchEvent(new Event('input'));
    if (amtEl) { amtEl.value = ''; amtEl.dataset.manualAmt = ''; }
  } else if (p.amount && amtEl) {
    amtEl.value = p.amount;
    amtEl.dataset.manualAmt = p.amount;
    amtEl.dispatchEvent(new Event('input'));
    if (litEl) litEl.value = '';
  }

  const fuelLabel = p.fuel ? p.fuel.replace('_',' ') : '';
  const valLabel  = p.liters ? (p.liters + ' L') : (p.amount ? '₹' + p.amount : '');
  const modeLabel = p.mode ? (' · ' + p.mode) : '';
  if (status) status.textContent = '✅ Set: ' + fuelLabel + ' ' + valLabel + modeLabel + ' — verify and tap 💾';
  toast('🎤 Voice: ' + fuelLabel + ' ' + valLabel + modeLabel, 'success');

  // Focus Record Sale button
  const recBtn = document.querySelector('.btn-accent.btn-block[onclick*="emp_recordSale"]');
  if (recBtn) recBtn.focus();
}
window.emp_applyVoiceParsed = emp_applyVoiceParsed;


function emp_recordDip() {
  const tankId = parseInt(document.getElementById('empDipTank')?.value);
  const r = parseFloat(document.getElementById('empDipVal')?.value);
  if (isNaN(r)||r<=0) { toast('Enter valid dip reading','error'); return; }
  if (r > 30000) { toast('Dip reading exceeds tank capacity limit','error'); return; }

  const dip = { id: Date.now(), tankId, reading: r, time: emp_time(), date: emp_today(), method: 'direct', employee: empState.user?.name || 'Employee' };

  // Save to employee session
  empState.dipReadings.unshift(dip);
  emp_saveSession();

  // Save to admin dip store + update tank level
  APP.data?.dipReadings?.unshift(dip);
  db.add('dipReadings', dip).catch(() => {});
  const tank = APP.data?.tanks?.find(t => parseInt(t.id) === parseInt(tankId));
  if (tank) { tank.current = r; tank.lastDip = emp_today() + ' ' + emp_time(); db.put('tanks', _tankForPut(tank)).catch(() => {}); }

  toast(`✅ Dip saved: Tank ${tankId} = ${fmt(r)} L`, 'success');
  emp_go('overview');
}

// ── CASH DENOMINATION HANDOVER ─────────────────────────────────────────────
// Shows a denomination entry form before shift submit.
// Employee fills in notes/coin counts; total is verified vs cash sales.
// empState.cashHandover is set when confirmed, then emp_submit() proceeds.
const EMP_DENOMS = [2000, 500, 200, 100, 50, 20, 10, 5, 2, 1];

function emp_showCashHandover(onConfirm) {
  const expectedCash = emp_totalCash();
  // Build denomination rows
  const rows = EMP_DENOMS.map(d => `
    <div style="display:grid;grid-template-columns:60px 1fr 90px;align-items:center;gap:8px;padding:6px 0;border-bottom:1px solid var(--border-light)">
      <span class="mono fw-700" style="color:var(--accent-light);font-size:14px">₹${d}</span>
      <input id="denom_${d}" class="form-input" type="number" inputmode="numeric" min="0" placeholder="0"
        style="padding:6px 10px;font-family:var(--mono);font-size:14px;text-align:center"
        oninput="emp_calcDenomTotal()" />
      <span class="mono" style="color:var(--text-2);font-size:12px;text-align:right" id="denom_sub_${d}">= ₹0</span>
    </div>`).join('');

  const overlay = document.createElement('div');
  overlay.id = 'cashHandoverOverlay';
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.82);backdrop-filter:blur(6px);z-index:10010;display:flex;align-items:center;justify-content:center;padding:16px;overflow-y:auto';
  overlay.innerHTML = `
    <div style="background:var(--bg-1);border-radius:16px;border:1px solid rgba(212,148,15,0.3);width:100%;max-width:420px">
      <div style="padding:16px 20px;border-bottom:1px solid var(--border)">
        <div style="font-size:15px;font-weight:800;color:var(--text-0)">💵 Cash Handover</div>
        <div style="font-size:11px;color:var(--text-3);margin-top:2px">Count notes & coins before submitting shift</div>
      </div>
      <div style="padding:16px 20px">
        <div style="background:rgba(212,148,15,0.07);border:1px solid rgba(212,148,15,0.2);border-radius:8px;padding:10px 14px;display:flex;justify-content:space-between;align-items:center;margin-bottom:14px">
          <span style="font-size:12px;font-weight:700;color:var(--text-2)">Expected Cash (from sales)</span>
          <span class="mono fw-800" style="font-size:16px;color:var(--accent-light)">${cur(expectedCash)}</span>
        </div>
        <div style="font-size:10px;font-weight:700;color:var(--text-3);text-transform:uppercase;letter-spacing:0.8px;margin-bottom:6px;display:grid;grid-template-columns:60px 1fr 90px;gap:8px">
          <span>Denom</span><span>Count</span><span style="text-align:right">Subtotal</span>
        </div>
        ${rows}
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-top:14px">
          <div style="background:var(--bg-2);border-radius:8px;padding:10px 12px;text-align:center">
            <div style="font-size:9px;font-weight:700;color:var(--text-3);text-transform:uppercase;letter-spacing:0.8px;margin-bottom:3px">Counted Total</div>
            <div class="mono fw-800" id="denomTotalDisplay" style="font-size:18px;color:var(--green)">₹0</div>
          </div>
          <div style="background:var(--bg-2);border-radius:8px;padding:10px 12px;text-align:center">
            <div style="font-size:9px;font-weight:700;color:var(--text-3);text-transform:uppercase;letter-spacing:0.8px;margin-bottom:3px">Variance</div>
            <div class="mono fw-800" id="denomVarianceDisplay" style="font-size:18px;color:var(--text-3)">₹0</div>
          </div>
        </div>
        <div style="margin-top:12px">
          <label style="font-size:11px;font-weight:700;color:var(--text-3);display:block;margin-bottom:5px;text-transform:uppercase;letter-spacing:0.5px">Remarks (optional)</label>
          <input id="handoverRemarks" class="form-input" placeholder="e.g. ₹50 short, manager informed" style="font-size:13px" />
        </div>
      </div>
      <div style="padding:12px 20px;display:flex;gap:8px;border-top:1px solid var(--border)">
        <button class="btn btn-ghost" style="flex:1" onclick="document.getElementById('cashHandoverOverlay').remove()">← Back</button>
        <button class="btn btn-accent" style="flex:1;padding:12px" onclick="emp_confirmCashHandover(${expectedCash})">✅ Confirm &amp; Submit</button>
      </div>
    </div>`;
  document.body.appendChild(overlay);
  // Focus first denom input
  setTimeout(() => document.getElementById('denom_2000')?.focus(), 100);
  // Store callback for confirm
  window._empHandoverCallback = onConfirm;
}

function emp_calcDenomTotal() {
  let total = 0;
  EMP_DENOMS.forEach(d => {
    const count = parseInt(document.getElementById('denom_' + d)?.value || '0') || 0;
    const sub = count * d;
    total += sub;
    const subEl = document.getElementById('denom_sub_' + d);
    if (subEl) subEl.textContent = '= ₹' + sub.toLocaleString('en-IN');
  });
  const totalEl = document.getElementById('denomTotalDisplay');
  const varEl   = document.getElementById('denomVarianceDisplay');
  const expEl   = document.querySelector('#cashHandoverOverlay .mono.fw-800[style*="accent-light"]');
  if (totalEl) totalEl.textContent = cur(total);
  // compute variance vs expected
  const expectedCash = emp_totalCash();
  const variance = total - expectedCash;
  if (varEl) {
    varEl.textContent = (variance > 0 ? '+' : '') + cur(variance);
    varEl.style.color = Math.abs(variance) < 1 ? 'var(--green)' : Math.abs(variance) <= 50 ? 'var(--orange)' : 'var(--red)';
  }
}

function emp_confirmCashHandover(expectedCash) {
  let total = 0;
  const breakdown = {};
  EMP_DENOMS.forEach(d => {
    const count = parseInt(document.getElementById('denom_' + d)?.value || '0') || 0;
    if (count > 0) { breakdown[d] = count; total += count * d; }
  });
  const remarks = document.getElementById('handoverRemarks')?.value?.trim() || '';
  const variance = total - expectedCash;
  // Store in empState for shift summary and server sync
  empState.cashHandover = { breakdown, total, expectedCash, variance, remarks, recordedAt: new Date().toISOString() };
  document.getElementById('cashHandoverOverlay').remove();
  if (typeof window._empHandoverCallback === 'function') window._empHandoverCallback();
}

function emp_confirmEnd() {
  const cc = Object.keys(empState.closeReadings).length, tn = emp_totalNozzles();

  // Check for reconciliation mismatches
  const mismatches = [];
  emp_myPumps().forEach(p => {
    const nozzleFuels = p.nozzleFuels || {};
    p.nozzles.forEach(n => {
      const ft = nozzleFuels[n] || p.fuelType;
      const r  = emp_nozzleRecon(p.id, n, ft);
      if (r.hasClose && !r.matched && (r.meterSold > 0 || r.salesSold > 0)) {
        mismatches.push({ pump: p.name, nozzle: n, fuel: (getFuel(ft)||{short:ft}).short, ...r });
      }
    });
  });

  if (mismatches.length > 0) {
    const rows = mismatches.map(m =>
      `<div style="padding:8px 12px;background:rgba(239,68,68,0.06);border-left:3px solid var(--red);border-radius:4px;margin-bottom:6px;font-size:12px">
        <strong style="color:var(--text-0)">${m.pump} · Nozzle ${m.nozzle} (${m.fuel})</strong>
        <div style="color:var(--text-2);margin-top:2px">Meter: <strong>${fmt(m.meterSold)} L</strong> · Sales recorded: <strong>${fmt(m.salesSold)} L</strong> · Gap: <strong style="color:var(--red)">${fmt(m.diff)} L</strong></div>
      </div>`
    ).join('');
    openModal('⚠️ Sales vs Reading Mismatch',
      `<p style="color:var(--text-2);font-size:13px;margin-bottom:12px">The meter readings don't match the quick sales entered. Please review before submitting.</p>
       ${rows}
       <p style="font-size:11px;color:var(--text-3);margin-top:12px">You can go back to Sales tab to add missing entries, or submit with this difference (manager will be notified).</p>`,
      `<button class="btn btn-ghost" onclick="closeModal()">← Fix Sales</button>
       <button class="btn btn-accent" onclick="closeModal();emp_showCashHandover(emp_submit)">Submit With Difference</button>`);
    return;
  }

  if (cc < tn) {
    openModal('⚠️ Closing Readings Pending',
      `<p style="color:var(--accent-light);font-weight:600;margin-bottom:12px">${tn-cc} nozzle closing readings are still pending.</p><p style="color:var(--text-2);font-size:13px;margin-bottom:16px">Are you sure you want to submit?</p>`,
      `<button class="btn btn-ghost" onclick="closeModal()">Go Back</button><button class="btn btn-accent" onclick="closeModal();emp_showCashHandover(emp_submit)">Submit Anyway</button>`);
  } else emp_showCashHandover(emp_submit);
}

async function emp_submit() {
  // FIX 36: prevent double-submit — user tapping Submit twice (slow connection)
  // would deduct tank levels twice and duplicate the shift history entry
  if (window._empSubmitInProgress) {
    toast('⏳ Shift close already in progress — please wait…', 'warning');
    return;
  }
  window._empSubmitInProgress = true;
  try {
    await _emp_submit_inner();
  } finally {
    window._empSubmitInProgress = false;
  }
}

async function _emp_submit_inner() {
  // ── FA-01: Flush any pending queued sales before submitting shift ──
  await emp_flushPendingSales().catch(() => {});
  // ── Refresh tanks from DB to get latest values before deducting ──
  try {
    const freshTanks = await db.getAll('tanks');
    if (freshTanks && freshTanks.length) APP.data.tanks = freshTanks.map(_normTank);
  } catch(e) { console.warn('[emp_submit] Tank refresh failed:', e); }

  // ── Sync pump readings & tank levels — per nozzle fuel type ──
  const tankDeductionsTotalByFuel = {}; // fuelType -> totalLiters
  
  
  
  emp_myPumps().forEach(pump => {
    const nozzleFuels = pump.nozzleFuels || {};
    const adminPump = APP.data.pumps.find(p => String(p.id) === String(pump.id));
    let pumpHasMeterReadings = false;

    pump.nozzles.forEach(n => {
      const key    = emp_key(pump.id, n);
      const openRaw  = empState.openReadings[key];
      const closeRaw = empState.closeReadings[key];
      const open   = openRaw  !== undefined ? parseFloat(openRaw)  : null;
      const close  = closeRaw !== undefined ? parseFloat(closeRaw) : null;
      const ft     = nozzleFuels[n] || pump.fuelType;
  // Only deduct when BOTH readings are present and close > open
      if (open !== null && close !== null && !isNaN(open) && !isNaN(close) && close > open) {
        const sold = close - open;
        pumpHasMeterReadings = true;
        tankDeductionsTotalByFuel[ft] = (tankDeductionsTotalByFuel[ft] || 0) + sold;
  } else {
  }

      // Update per-nozzle reading on admin pump (only with valid close)
      if (adminPump && close !== null && !isNaN(close) && close > 0) {
        if (!adminPump.nozzleReadings) adminPump.nozzleReadings = {};
        adminPump.nozzleReadings[n] = close;
      }
    });

    // If NO meter readings entered for this pump, use sales records as tank deduction source
    if (!pumpHasMeterReadings) {
      const pumpSales = empState.sales.filter(s => String(s.pump) === String(pump.id));
      pumpSales.forEach(s => {
        const ft = s.fuelType || pump.fuelType;
        tankDeductionsTotalByFuel[ft] = (tankDeductionsTotalByFuel[ft] || 0) + (s.liters || 0);
      });
    }

    // ── Save pump readings to server (always, using empState data directly) ──
    // Build nozzleReadings from empState.closeReadings (the actual meter values employee entered)
    const nozzleReadingsForServer = {};
    const nozzleOpenForServer = {};
    let hasAnyReading = false;
    // pump.nozzles is always a string[] from emp_myPumps e.g. ['A','B']
    const nozzleList = Array.isArray(pump.nozzles) ? pump.nozzles : ['A','B'];
    nozzleList.forEach(n => {
      const k = emp_key(pump.id, n);
      if (empState.closeReadings[k] !== undefined && empState.closeReadings[k] !== '') {
        nozzleReadingsForServer[n] = parseFloat(empState.closeReadings[k]) || 0;
        hasAnyReading = true;
      }
      if (empState.openReadings[k] !== undefined && empState.openReadings[k] !== '') {
        nozzleOpenForServer[n] = parseFloat(empState.openReadings[k]) || 0;
      }
    });

    if (hasAnyReading) {
      try {
        const tenant2 = (typeof mt_getActiveTenant === 'function') ? mt_getActiveTenant() : null;
        if (tenant2 && tenant2.id) {
          fetch('/api/public/reading/' + encodeURIComponent(tenant2.id), {
            method: 'POST', headers: {'Content-Type':'application/json'},
            body: JSON.stringify({
              pumpId: String(pump.id),
              nozzleReadings: nozzleReadingsForServer,
              nozzleOpen: nozzleOpenForServer
            })
          }).catch(e => console.warn('[emp reading] save failed:', e.message));
        }
      } catch(e) { console.warn('[emp reading]', e); }
    }

    // Update adminPump if available (same device as admin)
    if (adminPump) {
      Object.assign(adminPump.nozzleReadings = adminPump.nozzleReadings || {}, nozzleReadingsForServer);
      if (Object.keys(adminPump.nozzleReadings).length) {
        adminPump.currentReading = Object.values(adminPump.nozzleReadings).reduce((a, v) => a + v, 0);
        adminPump.openReading = Object.values(nozzleOpenForServer).reduce((a,v)=>a+(parseFloat(v)||0),0);
      }
      db.put('pumps', _pumpForPut(adminPump)).catch(() => {});
    }
  });

  // Deduct each fuel type from its tank once (combined across all pumps)
  const tankWritePromises = [];
  const deductLog = [];
  for (const [ft, liters] of Object.entries(tankDeductionsTotalByFuel)) {
    const tank = APP.data.tanks.find(t => t.fuelType === ft);
    if (tank && liters > 0) {
      const before = tank.current;
      tank.current = Math.max(0, tank.current - liters);
      tank.lastDip = emp_today();
      deductLog.push(getFuel(ft).short + ': -' + fmt(liters) + 'L (' + fmt(before) + 'L → ' + fmt(tank.current) + 'L)');
      // Try authenticated path first (same device as admin)
      tankWritePromises.push(db.put('tanks', _tankForPut(tank)).catch(() => {}));
    }
  }
  if (tankWritePromises.length > 0) {
    await Promise.all(tankWritePromises).catch(() => {});
  }
  // ── Always use public endpoint so tank deduction reaches DB even without auth ──
  try {
    const tenantTank = (typeof mt_getActiveTenant === 'function') ? mt_getActiveTenant() : null;
    if (tenantTank && tenantTank.id && Object.keys(tankDeductionsTotalByFuel).length > 0) {
      await fetch('/api/public/tank-deduct/' + encodeURIComponent(tenantTank.id), {
        method: 'POST', headers: {'Content-Type':'application/json'},
        body: JSON.stringify({ deductions: tankDeductionsTotalByFuel, shiftDate: emp_today() }) // FA-04: pass IST date so server can compare correctly
      }).catch(e => console.warn('[Tank deduct] server call failed:', e.message));
    }
  } catch(e) { console.warn('[Tank deduct] failed:', e); }
  // Broadcast to admin tab
  try { var bc2=new BroadcastChannel('fuelbunk_sync'); bc2.postMessage({type:'EMP_SUBMITTED',deductions:tankDeductionsTotalByFuel,employee:empState.user?empState.user.name:''}); bc2.close(); } catch(e) {}
  console.log('[FuelBunk] Deductions:', JSON.stringify(tankDeductionsTotalByFuel), '| Results:', deductLog.join(', '));

  // ── Compute mismatch balances and record against employee ──
  const empUser = empState.user;
  const mismatchEntries = [];
  emp_myPumps().forEach(pump => {
    const nozzleFuels = pump.nozzleFuels || {};
    pump.nozzles.forEach(n => {
      const ft   = nozzleFuels[n] || pump.fuelType;
      const recon = emp_nozzleRecon(pump.id, n, ft);
      if (recon.hasClose && !recon.matched && recon.meterSold > 0) {
        const fuel = getFuel(ft) || { short: ft, name: ft };
        const diffLiters = recon.meterSold - recon.salesSold; // positive = employee sold but didn't record
        const diffAmount = Math.abs(diffLiters) * ((APP.data?.prices || {})[ft] || 0);
        if (Math.abs(diffLiters) >= 0.1) {
          mismatchEntries.push({
            pump: pump.name, nozzle: n, fuelType: ft, fuelName: fuel.short,
            meterSold: recon.meterSold, salesSold: recon.salesSold,
            diffLiters, diffAmount, date: emp_today(), shift: empState.shift || ''
          });
        }
      }
    });
  });

  if (mismatchEntries.length > 0 && empUser) {
    const adminEmp = (APP.data?.employees || []).find(e => parseInt(e.id) === parseInt(empUser.id));
    if (adminEmp) {
      if (!adminEmp.balanceEntries) adminEmp.balanceEntries = [];
      adminEmp.balanceEntries.push({
        id: Date.now(), date: emp_today(), shift: empState.shift || '',
        entries: mismatchEntries,
        totalDiffLiters: mismatchEntries.reduce((a,e) => a + Math.abs(e.diffLiters), 0),
        totalDiffAmount: mismatchEntries.reduce((a,e) => a + e.diffAmount, 0),
        status: 'pending', // 'pending' | 'settled'
        settledAt: null, settledBy: null, note: ''
      });
      adminEmp.pendingBalance = (adminEmp.pendingBalance || 0) + mismatchEntries.reduce((a,e) => a + e.diffAmount, 0);
      db.put('employees', adminEmp).catch(() => {});
      APP.data.employees = APP.data.employees.map(e => e.id === adminEmp.id ? adminEmp : e);
    }
  }

  const submitLiters = emp_totalSold(), submitRev = emp_totalRev();
  const histEntry = {
    date: emp_today(), user: empUser?.name || '',
    liters: submitLiters, revenue: submitRev, salesCount: empState.sales.length,
    openReadings: { ...empState.openReadings }, closeReadings: { ...empState.closeReadings },
    sales: [...empState.sales], dipReadings: [...empState.dipReadings], timestamp: Date.now(),
    mismatches: mismatchEntries,
    employeeId: empUser?.id || 0,
  };
  empState.sessionHistory.unshift(histEntry);
  emp_saveHistory();
  // Also save to server so history persists across devices and cache clears
  emp_saveHistoryToServer(histEntry).catch(() => {});

  // ── Save nozzle meter log for this shift ──────────────────────────────────
  try {
    nozzleLog_recordFromShift(
      empUser?.name || '—',
      empState.shift || '—',
      emp_myPumps(),
      empState.openReadings,
      empState.closeReadings,
      empState.sales
    );
  } catch(nmErr) { console.warn('[NozzleLog] Failed to save:', nmErr); }
  empState.active = false; emp_clearSession();
  auditLog('reading_submit', { employee: empUser?.name, liters: submitLiters, revenue: submitRev, salesCount: empState.sales.length, mismatches: mismatchEntries.length });
  const msg = mismatchEntries.length > 0
    ? `Submitted with ${mismatchEntries.length} difference(s) — Admin notified.`
    : 'Submitted successfully! Tank inventory updated.';
  toast(msg, mismatchEntries.length > 0 ? 'warning' : 'success');

  // ── Re-sync APP.data from DB so admin sees the updated tank levels ──
  try {
    const [freshTanks, freshPumps, freshSales] = await Promise.all([
      db.getAll('tanks'),
      db.getAll('pumps'),
      db.getAll('sales'),
    ]);
    // Always update from DB regardless of array length
    APP.data.tanks = freshTanks.length ? freshTanks.map(_normTank) : APP.data.tanks;
    APP.data.pumps = freshPumps.length ? freshPumps.map(_normPump) : APP.data.pumps;
    if (freshSales.length) APP.data.sales = freshSales.sort((a,b) => b.id - a.id);
    console.log('[FuelBunk] Post-submit tanks:', APP.data.tanks.map(t => t.fuelType + ':' + t.current + 'L').join(', '));
  } catch(e) { console.warn('Post-submit DB refresh failed:', e); }

  empState.page = 'complete'; renderPage();
}

function emp_share() {
  const uname = sanitize(empState.user?.name||'');
  let t = `⛽ FuelBunk Pro — Report\n📅 ${emp_today()}\n👤 ${uname}\n\n📊 Summary:\n• Liters: ${fmt(emp_totalSold())} L\n• Revenue: ${cur(emp_totalRev())}\n• Sales: ${empState.sales.length}\n\n⛽ Pump-wise:\n`;
  emp_myPumps().forEach(p => { const s=emp_pumpSold(p.id); if(s>0) t+=`• ${sanitize(p.name)} (${EMP_FUEL[p.fuelType].split(' ')[0]}): ${fmt(s)} L\n`; });
  t += '\n— ' + (APP.data?.upiName || APP.tenant?.name || 'Fuel Station');
  if (navigator.share) navigator.share({title:'Report',text:t}).catch(()=>{});
  else navigator.clipboard?.writeText(t).then(()=>toast('Copied!','success')).catch(()=>{});
}

function emp_print() {
  const ts=emp_totalSold(), tr=emp_totalRev();
  const uname = sanitize(empState.user?.name||'');
  const rows = emp_myPumps().map(p => {
    const nr = p.nozzles.map(n => { const k=emp_key(p.id,n),o=empState.openReadings[k]||0,c=empState.closeReadings[k]||0; return `<tr><td style="padding-left:24px;color:#666">Nozzle ${n}</td><td style="text-align:right;font-family:monospace">${o.toFixed(1)}</td><td style="text-align:right;font-family:monospace">${c.toFixed(1)}</td><td style="text-align:right;font-family:monospace;font-weight:700">${(c-o).toFixed(1)}</td></tr>`; }).join('');
    return `<tr style="background:#f8f9fa"><td style="font-weight:700">${sanitize(p.name)} — ${EMP_FUEL[p.fuelType].split(' ')[0]}</td><td></td><td></td><td style="text-align:right;font-weight:700">${emp_pumpSold(p.id).toFixed(1)} L</td></tr>${nr}`;
  }).join('');
  const htmlContent = `<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Report</title><style>body{font-family:'Segoe UI',system-ui,sans-serif;padding:30px;font-size:12px;color:#333}h1{font-size:18px;text-align:center;margin-bottom:2px}h2{font-size:13px;text-align:center;color:#666;font-weight:400;margin-bottom:16px}.meta{text-align:center;font-size:11px;color:#888;margin-bottom:20px;padding-bottom:12px;border-bottom:2px solid #d4940f}table{width:100%;border-collapse:collapse;margin-bottom:16px}th{background:#f0f0f0;text-align:left;padding:8px;font-size:10px;text-transform:uppercase;border-bottom:2px solid #ddd}td{padding:6px 8px;border-bottom:1px solid #eee;font-size:12px}.total-row{background:#fff8e6;font-weight:700}.footer{text-align:center;font-size:10px;color:#aaa;margin-top:20px;border-top:1px solid #eee;padding-top:10px}</style></head><body><h1>${APP.data?.upiName || APP.tenant?.name || 'Fuel Station'}</h1><h2>Report — ${emp_today()}</h2><div class="meta">${emp_today()} · ${uname}</div><table><thead><tr><th>Pump / Nozzle</th><th style="text-align:right">Opening</th><th style="text-align:right">Closing</th><th style="text-align:right">Sold (L)</th></tr></thead><tbody>${rows}<tr class="total-row"><td>TOTAL</td><td></td><td></td><td style="text-align:right">${ts.toFixed(1)} L</td></tr></tbody></table><table><thead><tr><th>Metric</th><th style="text-align:right">Value</th></tr></thead><tbody><tr><td>Total Revenue</td><td style="text-align:right;font-weight:700">&#8377;${tr.toFixed(2)}</td></tr><tr><td>Sales</td><td style="text-align:right">${empState.sales.length}</td></tr><tr><td>Cash</td><td style="text-align:right">&#8377;${emp_totalCash().toFixed(2)}</td></tr></tbody></table><div class="footer">FuelBunk Pro — Auto Generated<br>Signature: ________________</div></body></html>`;
  const empBlob = new Blob([htmlContent], { type: 'text/html;charset=utf-8' });
  const empUrl = URL.createObjectURL(empBlob);
  const rpw = window.open(empUrl, '_blank');
  if (rpw && !rpw.closed) {
    setTimeout(() => { try { rpw.focus(); } catch(e){} URL.revokeObjectURL(empUrl); }, 2000);
  } else {
    const _close = '<button onclick="document.getElementById(\'reportOverlay\').remove()" style="background:#d4940f;color:#000;border:none;border-radius:6px;padding:6px 14px;font-weight:800;cursor:pointer;font-size:13px">&#10005; Close</button>';
    const _print = '<button onclick="document.getElementById(\'reportFrame\').contentWindow.print()" style="background:#22c55e;color:#fff;border:none;border-radius:6px;padding:6px 14px;font-weight:800;cursor:pointer;font-size:13px">&#128424; Print / Save PDF</button>';
    const _dl    = '<a href="' + empUrl + '" download="shift-report.html" style="background:#3b82f6;color:#fff;border:none;border-radius:6px;padding:6px 14px;font-weight:800;cursor:pointer;font-size:13px;text-decoration:none">&#8595; Download</a>';
    const _tb    = '<div style="display:flex;align-items:center;gap:10px;padding:10px 16px;background:#1a1a2e;border-bottom:2px solid #d4940f;flex-shrink:0">' + _close + '<span style="color:#fff;font-size:13px;font-weight:600;flex:1">FuelBunk Pro &#8212; Report</span>' + _print + _dl + '</div>';
    const _ov    = document.createElement('div');
    _ov.id = 'reportOverlay';
    _ov.style.cssText = 'position:fixed;inset:0;z-index:99999;background:#fff;display:flex;flex-direction:column';
    _ov.innerHTML = _tb + '<iframe id="reportFrame" src="' + empUrl + '" style="flex:1;border:none;width:100%;height:100%"></iframe>';
    const _ex = document.getElementById('reportOverlay'); if (_ex) _ex.remove();
    document.body.appendChild(_ov);
  }
}

