function exportPLCSV() {
  const D = APP.data;
  const totalRev = D.sales.reduce((a,s) => a+s.amount, 0);
  const cogs = D.sales.reduce((a,s) => a+s.liters*(D.purchasePrices[s.fuelType]||0), 0);
  const gross = totalRev - cogs;
  const salary = D.employees.reduce((a,e) => a+(e.salary||0), 0);
  const expenseMap = {};
  D.expenses.forEach(e => {
    if (e.source === 'fuel_purchase') return;
    const cat = e.category || 'Other';
    expenseMap[cat] = (expenseMap[cat]||0) + (e.amount||0);
  });
  const totalExp = salary + Object.values(expenseMap).reduce((a,v)=>a+v,0);
  const rows = [
    ['Total Revenue', totalRev],
    ['Cost of Goods Sold', cogs],
    ['Gross Profit', gross],
    ['Staff Salaries', salary],
    ...Object.entries(expenseMap).map(([k,v]) => [k, v]),
    ['Total Expenses', totalExp],
    ['NET PROFIT', gross - totalExp],
  ];
  exportCSV('pl-report-' + today() + '.csv',
    ['Item', 'Amount (INR)'], rows);
}

