// ── DATA INIT ────────────────────────────────────────────────
async function seedDatabase() {
  for (const t of SEED.tanks) await db.put('tanks', _tankForPut(t)).catch(() => {});
  for (const p of SEED.pumps) await db.put('pumps', _pumpForPut(p)).catch(() => {});
  for (const s of SEED.shifts) await db.put('shifts', s).catch(() => {});
  await db.bulkPut('employees', SEED.employees).catch(() => {});
  await db.bulkPut('sales', SEED.sales).catch(() => {});
  await db.bulkPut('creditCustomers', SEED.creditCustomers).catch(() => {});
  await db.bulkPut('expenses', SEED.expenses).catch(() => {});
  await db.bulkPut('fuelPurchases', SEED.fuelPurchases).catch(() => {});
  await db.bulkPut('dipReadings', SEED.dipReadings).catch(() => {});
  await db.setSetting('prices', SEED.prices);
  await db.setSetting('purchasePrices', SEED.purchasePrices);
  await db.setSetting('seeded', true);
}

async function loadData() {
  try {
    await db.ready;
  } catch (e) {
    console.error('IndexedDB init failed:', e);
    APP.data = { ...SEED };
    return;
  }

  if (!db.db) {
    console.warn('No DB connection, using seed data');
    APP.data = { ...SEED };
    return;
  }

  // ── PARALLEL FETCH: fire all requests simultaneously ─────────────────────
  // Previously sequential (~18 round-trips × 300ms = 6s). Now one wave.
  // Fix 01C: limit date-heavy stores to last 60 days on dashboard load.
  // Reports tab uses its own date-range queries — completely unaffected.
  // FIX 28: compute 60-day cutoff from IST today, not UTC Date.now() — prevents
  //          off-by-one during the 18:30–00:00 UTC window (midnight IST to midnight UTC).
  const from60 = (() => {
    const t = (typeof today === 'function' ? today() : new Date().toLocaleString('en-CA', { timeZone: 'Asia/Kolkata' }).slice(0, 10));
    const [y, m, d] = t.split('-').map(Number);
    const dt = new Date(y, m - 1, d - 60);
    return `${dt.getFullYear()}-${String(dt.getMonth() + 1).padStart(2, '0')}-${String(dt.getDate()).padStart(2, '0')}`;
  })();
  const [
    seeded,
    razorpayKey,
    rawTanks, rawPumps, rawShifts, rawEmployees,
    rawSales, rawCredit, rawCreditTxns, rawExpenses, rawPurchases, rawDip,
    prices, purchasePrices, priceHistory,
    upiVPA, upiName, stationCode, omcName,
    serverAlloc, savedRoster, savedAtt,
    savedTaxRates, savedAdvances, savedBankRecon,
    waPhone, waApiKey
  ] = await Promise.all([
    db.getSetting('seeded').catch(() => null),
    db.getSetting('razorpayKey').catch(() => ''),
    db.getAll('tanks').catch(() => []),
    db.getAll('pumps').catch(() => []),
    db.getAll('shifts').catch(() => []),
    db.getAll('employees').catch(() => []),
    db.getAll('sales',          { from: from60 }).catch(() => []),
    db.getAll('creditCustomers').catch(() => []),
    db.getAll('creditTransactions').catch(() => []),
    db.getAll('expenses',       { from: from60 }).catch(() => []),
    db.getAll('fuelPurchases',  { from: from60 }).catch(() => []),
    db.getAll('dipReadings',    { from: from60 }).catch(() => []),
    db.getSetting('prices').catch(() => null),
    db.getSetting('purchasePrices').catch(() => null),
    db.getSetting('price_history').catch(() => []),
    db.getSetting('upiVPA').catch(() => ''),
    db.getSetting('upiName').catch(() => ''),
    db.getSetting('stationCode').catch(() => ''),
    db.getSetting('omcName').catch(() => ''),
    db.getSetting('allocations').catch(() => null),
    db.getSetting('shift_roster').catch(() => null),
    db.getSetting('attendance_data').catch(() => null),
    db.getSetting('fuelTaxRates').catch(() => null),
    db.getSetting('advances_data').catch(() => null),
    db.getSetting('bank_recon_data').catch(() => null),
    db.getSetting('waPhone').catch(() => ''),
    db.getSetting('waApiKey').catch(() => ''),
  ]);

  APP.data.razorpayKey = razorpayKey || '';
  if (!seeded) await seedDatabase().catch(() => {});

  try {
    // Derive purchasePrices from fuelPurchases if not saved
    let resolvedPurchasePrices = purchasePrices;
    if (!resolvedPurchasePrices || Object.keys(resolvedPurchasePrices).length === 0) {
      if (rawPurchases.length > 0) {
        const derived = {};
        [...rawPurchases].sort((a,b) => (b.id||0)-(a.id||0)).forEach(p => {
          if (p.fuelType && p.rate && !derived[p.fuelType]) derived[p.fuelType] = p.rate;
        });
        if (Object.keys(derived).length > 0) resolvedPurchasePrices = derived;
      }
      if (!resolvedPurchasePrices || Object.keys(resolvedPurchasePrices).length === 0)
        resolvedPurchasePrices = SEED.purchasePrices;
    }

    APP.data = {
      tanks: rawTanks.map(_normTank),
      pumps: rawPumps.map(_normPump),
      // ── Shift Manager guard: rawShifts/rawEmployees are [] for employee tokens ──
      // If we already fetched real data via staff-data endpoint, keep it.
      shifts: (window._mgrShifts && window._mgrShifts.length > 0)
        ? window._mgrShifts
        : rawShifts,
      employees: (window._mgrEmployees && window._mgrEmployees.length > 0)
        ? window._mgrEmployees
        : rawEmployees.map(function(e) {
            if (!e.permissions && e.data_json) {
              try { const j = JSON.parse(e.data_json || '{}'); e.permissions = j.permissions || {}; } catch { e.permissions = {}; }
            }
            if (!e.permissions) e.permissions = {};
            if (e.joinDate === undefined && e.join_date) e.joinDate = e.join_date;
            if (e.color === undefined && e.data_json) {
              try { e.color = JSON.parse(e.data_json).color || ''; } catch {}
            }
            return e;
          }),
      sales: rawSales.sort((a, b) => b.id - a.id).map(function(s) {
        // Normalise: DB returns employeeName/employee_name, admin.js uses s.employee
        if (!s.employee) s.employee = s.employeeName || s.employee_name || '';
        return s;
      }),
      creditCustomers: rawCredit.map(function(c) {
        c.outstanding = parseFloat(c.outstanding !== undefined ? c.outstanding : (c.balance || 0));
        c.limit       = parseFloat(c.limit       !== undefined ? c.limit       : (c.credit_limit || 0));
        if (!c.lastPayment) c.lastPayment = c.last_payment || '';
        if (!c.phone) c.phone = '';
        if (!c.type) c.type = 'Individual';
        return c;
      }),
      expenses: rawExpenses.sort((a, b) => b.id - a.id).map(function(e) {
        if (e.desc === undefined && e.description) e.desc = e.description;
        if (e.total === undefined) e.total = e.amount || 0;
        return e;
      }),
      fuelPurchases: rawPurchases.sort((a, b) => b.id - a.id).map(function(p) {
        if (p.total === undefined || p.total === null) p.total = p.amount || 0;
        if (!p.invoice) p.invoice = p.invoice_no || p.invoiceNo || '';
        if (!p.fuelType) p.fuelType = p.fuel_type || '';
        if (p.liters === undefined) p.liters = 0;
        if (p.rate === undefined) p.rate = 0;
        return p;
      }),
      dipReadings: rawDip.sort((a, b) => b.id - a.id).map(function(d) { if (!d.tankId && d.tank_id) d.tankId = d.tank_id; return d; }),
      prices: prices || SEED.prices,
      purchasePrices: resolvedPurchasePrices,
      weekly: [],
      creditTransactions: (rawCreditTxns || []).sort((a,b) => (b.id||0)-(a.id||0)),
      priceHistory: (priceHistory || []),
      upiVPA: upiVPA || SEED.upiVPA,
      upiName: upiName || SEED.upiName,
      stationCode: stationCode || '',
      omcName: omcName || '',
      waPhone: waPhone || '',
      waApiKey: waApiKey || '',
      gstin: '',
      legalName: '',
      stateCode: '29',
      loyaltyEarnRate: 1,
      loyaltyRedeemRate: 50,
      loyaltyMinRedeem: 100,
    };

    // ── Allocations ───────────────────────────────────────────────────────────
    try {
      if (serverAlloc && typeof serverAlloc === 'object' && Object.keys(serverAlloc).length > 0) {
        allocations = serverAlloc;
      }
      try {
        const todayStr = (()=>{const _d=new Date();return _d.getFullYear()+'-'+String(_d.getMonth()+1).padStart(2,'0')+'-'+String(_d.getDate()).padStart(2,'0');})();
        const todayKeys = Object.keys(allocations).filter(k =>
          k.startsWith(todayStr + '_') &&
          typeof allocations[k] === 'object' &&
          Object.values(allocations[k]).some(v => v && parseInt(v) > 0)
        );
        if (todayKeys.length > 0) {
          todayKeys.sort((a, b) =>
            Object.values(allocations[b]).filter(v => v && parseInt(v) > 0).length -
            Object.values(allocations[a]).filter(v => v && parseInt(v) > 0).length
          );
          allocShift = todayKeys[0].replace(todayStr + '_', '');
        }
      } catch {}
      if (APP.data?.pumps) {
        const validNozzleKeys = new Set();
        APP.data.pumps.forEach(p => {
          const labels = p.nozzleLabels || (p.nozzles === 1 ? ['A'] : p.nozzles === 2 ? ['A','B'] : ['A','B','C'].slice(0, p.nozzles));
          labels.forEach(n => validNozzleKeys.add(`${String(p.id)}_${n}`));
        });
        if (validNozzleKeys.size > 0) {
          let pruned = false;
          Object.keys(allocations).forEach(dk => {
            if (typeof allocations[dk] !== 'object') { delete allocations[dk]; pruned = true; return; }
            Object.keys(allocations[dk]).forEach(key => {
              if (!validNozzleKeys.has(key)) { delete allocations[dk][key]; pruned = true; }
            });
            if (Object.keys(allocations[dk]).length === 0) { delete allocations[dk]; pruned = true; }
          });
          if (pruned) saveAllocations();
        }
      }
    } catch(allocErr) {
      console.warn('[Alloc] Failed to load from server:', allocErr.message);
    }

    // ── Roster & Attendance ───────────────────────────────────────────────────
    if (savedRoster && typeof savedRoster === 'object') window._rosterData = savedRoster;
    if (savedAtt && typeof savedAtt === 'object') window._attendanceData = savedAtt;
    if (Array.isArray(savedAdvances)) window._advancesData = savedAdvances;
    if (savedBankRecon && typeof savedBankRecon === 'object') window._bankReconData = savedBankRecon;
    // Load nozzle meter log
    try {
      const savedNozzleLog = await db.getSetting('nozzle_meter_log').catch(()=>null);
      if (Array.isArray(savedNozzleLog)) window._nozzleMeterLog = savedNozzleLog;
    } catch(e) {}
    // Load lubes catalogue + sales
    try {
      const [savedLubeProds, savedLubeSales] = await Promise.all([
        db.getSetting('lubes_products').catch(()=>null),
        db.getSetting('lubes_sales').catch(()=>null),
      ]);
      if (Array.isArray(savedLubeProds)) window._lubesProducts = savedLubeProds;
      if (Array.isArray(savedLubeSales)) window._lubesSales    = savedLubeSales;
    } catch(e) {}
    // Persist WA log across sessions
    try {
      const savedWaLog = await db.getSetting('wa_log').catch(()=>null);
      if (Array.isArray(savedWaLog) && savedWaLog.length) window._waLog = savedWaLog;
    } catch(e) {}
    // Load GST settings
    try {
      const [gstin, legalName, stateCode] = await Promise.all([
        db.getSetting('gstin').catch(()=>''),
        db.getSetting('legalName').catch(()=>''),
        db.getSetting('stateCode').catch(()=>'29'),
      ]);
      if (gstin)     APP.data.gstin     = gstin;
      if (legalName) APP.data.legalName = legalName;
      if (stateCode) APP.data.stateCode = stateCode;
    } catch(e) {}
    // Load Day-Lock flags — scan settings for keys like day_lock_YYYY-MM-DD
    try {
      const dayLocks = {};
      const allSettings = await db.getAll('settings').catch(()=>[]);
      (Array.isArray(allSettings) ? allSettings : []).forEach(s => {
        if (s && s.key && s.key.startsWith('day_lock_') && s.value === 'true') {
          dayLocks[s.key.replace('day_lock_', '')] = true;
        }
      });
      APP.data.dayLocks = dayLocks;
    } catch(e) { APP.data.dayLocks = {}; }
    // Load loyalty settings
    try {
      const [loyaltyEarnRate, loyaltyRedeemRate, loyaltyMinRedeem] = await Promise.all([
        db.getSetting('loyaltyEarnRate').catch(()=>1),
        db.getSetting('loyaltyRedeemRate').catch(()=>50),
        db.getSetting('loyaltyMinRedeem').catch(()=>100),
      ]);
      APP.data.loyaltyEarnRate   = loyaltyEarnRate  || 1;
      APP.data.loyaltyRedeemRate = loyaltyRedeemRate || 50;
      APP.data.loyaltyMinRedeem  = loyaltyMinRedeem  || 100;
    } catch(e) {}
    // Load payroll for current month
    try {
      const now2 = new Date();
      const pm = now2.getMonth()+1, py = now2.getFullYear();
      const savedPayrollRaw = await db.getSetting('payroll_'+py+'_'+pm).catch(()=>null);
      if (savedPayrollRaw && typeof savedPayrollRaw === 'object') window._payrollSaved = savedPayrollRaw;
    } catch(e) {}

    // ── Load Fuel Tax Rates ───────────────────────────────────────────────────
    APP.data.fuelTaxRates = (Array.isArray(savedTaxRates) && savedTaxRates.length > 0)
      ? savedTaxRates
      : [
          { fuelType: 'petrol',         taxName: 'ZLST', rate: 29.84 },
          { fuelType: 'diesel',         taxName: 'ZLST', rate: 21.17 },
          { fuelType: 'premium_petrol', taxName: 'ZLST', rate: 18.00 },
        ];

    // ── Backfill: ensure every fuel purchase has a matching expense entry ──
    // This handles purchases entered before the auto-expense feature was added
    const existingPurchaseExpIds = new Set(
      APP.data.expenses.filter(e => e.source === 'fuel_purchase').map(e => e.purchaseId)
    );
    const missingPurchases = APP.data.fuelPurchases.filter(p => !existingPurchaseExpIds.has(p.id));
    if (missingPurchases.length > 0) {
      const newExpenses = missingPurchases.map(p => {
        const fi = getFuel(p.fuelType) || { short: p.fuelType };
        return {
          id: p.id + 0.1, // stable ID derived from purchase
          date: p.date || today(),
          category: 'Fuel Purchase',
          desc: `${fi.short} — ${fmt(p.liters)}L @ ₹${p.rate}/L${p.invoice ? ' · ' + p.invoice : ''}`,
          amount: p.total || (p.liters * p.rate),
          source: 'fuel_purchase',
          purchaseId: p.id,
        };
      });
      for (const e of newExpenses) {
        APP.data.expenses.push(e);
        db.add('expenses', e).catch(() => {});
      }
      APP.data.expenses.sort((a, b) => (b.id || 0) - (a.id || 0));
    }
    // ── Write employee cache for login screen (survives logout + new sessions) ──
    try {
      const empCacheData = (APP.data.employees || []).map(function(e) {
        return { id: e.id, name: e.name, role: e.role, shift: e.shift, pinHash: e.pinHash || null, permissions: e.permissions || {} };
      });
      if (empCacheData.length > 0) {
        localStorage.setItem('fb_emp_cache', JSON.stringify(empCacheData));
      }
    } catch {}
    // ── Restore Shift Manager data if loadData() overwrote it ────────────────
    if (window._mgrEmployees && window._mgrEmployees.length > 0) {
      APP.data.employees = window._mgrEmployees;
    }
    if (window._mgrShifts && window._mgrShifts.length > 0) {
      APP.data.shifts = window._mgrShifts;
    }

    // ── If employee token got empty arrays, fetch staff-data for Shift Manager ──
    if (APP.role === 'employee' && empState.active && empState.user?.role === 'Shift Manager'
        && (!APP.data.employees || APP.data.employees.length === 0)) {
      _fetchMgrData().then(() => {
        if (typeof renderPage === 'function') try { renderPage(); } catch(e) {}
      }).catch(() => {});
    }

    // If employee is already in the app when loadData finishes (background preload),
    // trigger a silent re-render ONLY if we actually have employee data to show.
    // CRITICAL: Do NOT re-render if this is a stale background preload that finished
    // after a Shift Manager login — _fetchMgrData may still be in-flight and
    // APP.data.employees would be empty, causing the "No staff" flash.
    if (APP.role === 'employee' && empState.active && typeof renderPage === 'function') {
      const isMgrMissingData = empState.user?.role === 'Shift Manager'
        && (!APP.data.employees || APP.data.employees.length === 0);
      if (!isMgrMissingData) {
        try { renderPage(); } catch(e) {}
      }
    }
  } catch (e) {
    console.error('Data load failed, using seed data:', e);
    APP.data = { ...SEED };
  }
}



// ═══════════════════════════════════════════════════════════════════════
// ── LUBES SALES — Employee Portal ────────────────────────────────────
// ═══════════════════════════════════════════════════════════════════════
function emp_renderLubes() {
  if (!window._lubesProducts) window._lubesProducts = [];
  const allProds = window._lubesProducts.filter(p => p.active !== false);
  const myName   = empState.user?.name || '';
  const today    = emp_today();

  if (allProds.length === 0) {
    return `<div style="text-align:center;padding:40px 20px;color:var(--text-3)">
      <div style="font-size:40px;margin-bottom:12px">🛢️</div>
      <div class="fw-700" style="color:var(--text-1);margin-bottom:6px">No Products Catalogued</div>
      <div style="font-size:12px">Ask admin to add products in the Lubes section.</div>
    </div>`;
  }

  const cards = allProds.map(p => {
    const isOut = (p.stock||0) <= 0;
    const isLow = !isOut && (p.stock||0) <= (p.minStock||5);
    const stockColor = isOut ? 'var(--red)' : isLow ? 'var(--orange)' : 'var(--green)';
    const stockLabel = isOut ? '❌ Out of Stock' : (isLow ? '⚠️ Low: ' : '✅ ') + p.stock + ' ' + sanitize(p.unit||'');
    return `<div class="card" style="padding:14px;border:1px solid \${isOut?'rgba(239,68,68,0.3)':isLow?'rgba(249,115,22,0.3)':'var(--border)'};margin-bottom:10px">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:10px">
        <div>
          <div class="fw-800" style="color:var(--text-0);font-size:14px">\${sanitize(p.name)}</div>
          <div style="font-size:10px;color:var(--text-3);margin-top:2px">\${sanitize(p.brand||'')}\${p.category?' · '+sanitize(p.category):''}</div>
        </div>
        <div style="text-align:right;flex-shrink:0;margin-left:12px">
          <div class="mono fw-800" style="color:var(--accent-light);font-size:18px">₹\${(p.sellingPrice||0).toFixed(2)}</div>
          <div style="font-size:9px;color:var(--text-3)">per \${sanitize(p.unit||'unit')}</div>
        </div>
      </div>
      <div style="display:flex;justify-content:space-between;align-items:center">
        <div style="font-size:11px;font-weight:700;color:\${stockColor}">\${stockLabel}</div>
        <button \${isOut?'disabled':''} onclick="emp_openLubeSell(\${p.id})"
          style="padding:9px 18px;background:\${isOut?'var(--bg-2)':'rgba(212,148,15,0.15)'};border:1px solid \${isOut?'var(--border)':'rgba(212,148,15,0.4)'};color:\${isOut?'var(--text-3)':'var(--accent-light)'};border-radius:8px;font-size:12px;font-weight:700;cursor:\${isOut?'not-allowed':'pointer'};transition:all 0.15s">
          🛒 Sell
        </button>
      </div>
    </div>`;
  }).join('');

  // Today's sales by this employee
  const mySales  = (window._lubesSales||[]).filter(s => s.date === today && s.employee === myName);
  const myRevenue = mySales.reduce((a,s)=>a+s.amount, 0);
  const modeMap   = {cash:'💵',upi:'📱',card:'💳',credit:'🏢'};
  const salesRows = mySales.length > 0
    ? mySales.map(s=>`<div style="display:flex;justify-content:space-between;align-items:center;padding:8px 0;border-bottom:1px solid var(--border-light)">
        <div><div class="fw-700" style="font-size:12px;color:var(--text-0)">\${sanitize(s.productName||'')}</div>
        <div style="font-size:10px;color:var(--text-3)">\${s.qty} \${sanitize(s.unit||'')} · \${s.time||''} · \${modeMap[s.mode]||s.mode||''} \${sanitize(s.customer||'')}</div></div>
        <div class="mono fw-800" style="color:var(--green)">₹\${(s.amount||0).toFixed(2)}</div>
      </div>`).join('')
    : `<div style="text-align:center;padding:16px;color:var(--text-3);font-size:12px">No lubes sales recorded today</div>`;

  return `
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px">
      <div><h3 class="fw-800" style="color:var(--text-0);font-size:18px">🛢️ Lubes Sales</h3>
      <p style="font-size:11px;color:var(--text-3);margin-top:2px">\${allProds.length} products · tap Sell to record</p></div>
    </div>
    \${cards}
    <div class="card"><div class="card-head"><h4>📋 My Sales Today</h4>\${myRevenue>0?'<span class=\"mono fw-800\" style=\"color:var(--green)\">₹'+myRevenue.toFixed(2)+'</span>':''}
    </div><div class="card-body" style="padding:0 16px">\${salesRows}</div></div>
  `;
}
window.emp_renderLubes = emp_renderLubes;

function emp_openLubeSell(productId) {
  const p = (window._lubesProducts||[]).find(x => x.id === productId);
  if (!p) return;
  if ((p.stock||0) <= 0) { toast('Out of stock — please inform admin to restock', 'error'); return; }
  const modeOpts = ['cash','upi','card','credit'].map(m=>`<option value="${m}">${m.toUpperCase()}</option>`).join('');
  openModal(`🛒 Sell — ${sanitize(p.name)}`,
    `<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:14px">
      <div style="padding:12px;background:var(--bg-0);border-radius:8px;text-align:center">
        <div class="mono fw-800" style="color:var(--green);font-size:20px">${p.stock||0} ${sanitize(p.unit||'')}</div>
        <div style="font-size:10px;color:var(--text-3)">In Stock</div>
      </div>
      <div style="padding:12px;background:var(--bg-0);border-radius:8px;text-align:center">
        <div class="mono fw-800" style="color:var(--accent-light);font-size:20px">₹${(p.sellingPrice||0).toFixed(2)}</div>
        <div style="font-size:10px;color:var(--text-3)">Per ${sanitize(p.unit||'unit')}</div>
      </div>
    </div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px">
      <div class="form-group"><label class="form-label">Qty (${sanitize(p.unit||'unit')}) *</label>
        <input class="form-input mono" type="number" id="els_qty" placeholder="1" min="0.1" step="0.1" max="${p.stock}"
          oninput="emp_calcLubeTotal(${p.sellingPrice||0})"
          style="font-size:20px;font-weight:800;text-align:center;letter-spacing:2px" />
      </div>
      <div class="form-group"><label class="form-label">Rate ₹/${sanitize(p.unit||'unit')}</label>
        <input class="form-input mono" type="number" id="els_rate" value="${p.sellingPrice||0}" step="0.01"
          oninput="emp_calcLubeTotal()"
          style="font-size:20px;font-weight:800;text-align:center;letter-spacing:2px" />
      </div>
    </div>
    <div id="els_total" style="padding:14px;background:rgba(212,148,15,0.08);border-radius:8px;text-align:center;margin:10px 0;font-size:11px;color:var(--text-3)">Enter quantity to see total</div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px">
      <div class="form-group"><label class="form-label">Payment Mode</label><select class="form-input" id="els_mode">${modeOpts}</select></div>
      <div class="form-group"><label class="form-label">Customer (opt.)</label><input class="form-input" id="els_cust" placeholder="Name / Vehicle" /></div>
    </div>`,
    `<button class="btn btn-ghost" onclick="closeModal()">Cancel</button><button class="btn btn-accent" onclick="emp_saveLubeSale(${productId})">💰 Record Sale</button>`
  );
}
window.emp_openLubeSell = emp_openLubeSell;

function emp_calcLubeTotal(defaultRate) {
  const qty  = parseFloat(document.getElementById('els_qty')?.value) || 0;
  const rate = parseFloat(document.getElementById('els_rate')?.value || (defaultRate || 0));
  const el   = document.getElementById('els_total');
  if (!el) return;
  if (qty > 0 && rate > 0) {
    el.innerHTML = `<div class="mono fw-800" style="font-size:26px;color:var(--accent-light)">₹${(qty*rate).toFixed(2)}</div><div style="font-size:10px;color:var(--text-3);margin-top:2px">Total Amount</div>`;
  }
}
window.emp_calcLubeTotal = emp_calcLubeTotal;

async function emp_saveLubeSale(productId) {
  const qty  = parseFloat(document.getElementById('els_qty')?.value);
  const rate = parseFloat(document.getElementById('els_rate')?.value);
  const mode = document.getElementById('els_mode')?.value || 'cash';
  const cust = (document.getElementById('els_cust')?.value || '').trim();
  if (isNaN(qty) || qty <= 0)    { toast('Please enter a valid quantity', 'error'); return; }
  if (isNaN(rate) || rate <= 0)  { toast('Please enter a valid rate', 'error'); return; }
  const p = (window._lubesProducts||[]).find(x => x.id === productId);
  if (!p) { toast('Product not found — please refresh', 'error'); return; }
  if (qty > p.stock)             { toast(`Only ${p.stock} ${p.unit||''} in stock`, 'error'); return; }
  const amount = +(qty * rate).toFixed(2);
  const now2   = new Date();
  if (!window._lubesSales) window._lubesSales = [];
  window._lubesSales.unshift({
    id: Date.now(),
    date: now2.toISOString().slice(0, 10),
    time: now2.toTimeString().slice(0, 5),
    productId, productName: p.name,
    qty, unit: p.unit || '',
    rate, amount,
    customer: cust,
    mode,
    employee: empState.user?.name || '',
  });
  p.stock = +(p.stock - qty).toFixed(3);
  try {
    await Promise.all([
      db.setSetting('lubes_products', window._lubesProducts),
      db.setSetting('lubes_sales',    window._lubesSales),
    ]);
  } catch(e) { console.warn('[emp_saveLubeSale]', e.message); }
  closeModal();
  toast(`✅ Sold ${qty} ${p.unit||''} ${p.name} — ₹${amount.toFixed(2)}`, 'success');
  // Low stock warning
  if (p.stock <= (p.minStock||5)) toast(`⚠️ Low stock alert: only ${p.stock} ${p.unit||''} left — inform admin`, 'warning');
  renderPage();
}
window.emp_saveLubeSale = emp_saveLubeSale;


// ═══════════════════════════════════════════════════════════════════════
// ── STAFF VIEW — Shift Manager Portal ────────────────────────────────
// ═══════════════════════════════════════════════════════════════════════
function emp_renderStaffView() {
  const D = APP.data;
  if (!D) return '<div style="padding:20px;color:var(--text-3)">Loading data...</div>';

  // ── Sub-tab state ─────────────────────────────────────────────────
  if (!window._empStaffTab) window._empStaffTab = 'allocation';
  const tab = window._empStaffTab;
  const today = emp_today();

  const tabBar = `<div style="display:flex;gap:3px;background:var(--bg-1);border-radius:var(--radius);padding:4px;margin-bottom:16px;border:1px solid var(--border-light)">
    ${[
      {id:'allocation',icon:'⛽',l:'Allocation'},
      {id:'roster',    icon:'🗓️',l:'Roster'},
      {id:'attendance',icon:'✅',l:'Attendance'},
      {id:'directory', icon:'📋',l:'Directory'},
    ].map(t=>`<button onclick="window._empStaffTab='${t.id}';renderPage()"
      style="flex:1;padding:8px 4px;border-radius:calc(var(--radius) - 2px);border:none;background:${tab===t.id?'var(--bg-3)':'transparent'};color:${tab===t.id?'var(--accent-light)':'var(--text-3)'};font-family:var(--font);font-size:9px;font-weight:700;cursor:pointer;letter-spacing:0.3px;text-transform:uppercase;white-space:nowrap">
      <span style="font-size:13px;display:block;margin-bottom:1px">${t.icon}</span>${t.l}
    </button>`).join('')}
  </div>`;

  const hdr = `<div style="margin-bottom:12px">
    <h3 class="fw-800" style="color:var(--text-0);font-size:18px">👥 Staff &amp; Allocation</h3>
    <p style="font-size:11px;color:var(--text-3);margin-top:2px">${today} · ${(D.employees||[]).length} employees</p>
  </div>`;

  // ═══════════════════════════════════════════════════════════════
  // TAB: ALLOCATION
  // ═══════════════════════════════════════════════════════════════
  if (tab === 'allocation') {
    const curAllocShift = window.allocShift || (D.shifts[0]?.name || 'Morning');
    const curAllocDate  = window.allocDate  || today;

    // Week anchor
    if (!window.allocWeekAnchor) {
      const d = new Date(); const day = d.getDay(); const diff = (day===0?-6:1-day);
      d.setDate(d.getDate()+diff); window.allocWeekAnchor = d.toISOString().slice(0,10);
    }
    const weekStart = new Date(window.allocWeekAnchor);
    const weekDays  = Array.from({length:7},(_,i)=>{const d=new Date(weekStart);d.setDate(d.getDate()+i);return d.toISOString().slice(0,10);});
    const pvW = new Date(weekStart); pvW.setDate(pvW.getDate()-7);
    const nxW = new Date(weekStart); nxW.setDate(nxW.getDate()+7);
    if (!weekDays.includes(curAllocDate)) window.allocDate = weekDays.includes(today) ? today : weekDays[0];

    const shiftTabs = (D.shifts||[]).map(s=>
      `<button onclick="window.allocShift='${s.name}';renderPage()"
        style="padding:6px 12px;border-radius:6px;border:1px solid ${curAllocShift===s.name?'var(--accent)':'var(--border)'};background:${curAllocShift===s.name?'rgba(212,148,15,0.12)':'transparent'};color:${curAllocShift===s.name?'var(--accent-light)':'var(--text-3)'};font-size:11px;font-weight:700;cursor:pointer">
        ${s.name}<span style="font-size:9px;opacity:0.6;margin-left:4px">${s.start}–${s.end}</span>
      </button>`).join('');

    const weekLabel = new Date(weekDays[0]).toLocaleDateString('en-IN',{day:'numeric',month:'short'})+' – '+new Date(weekDays[6]).toLocaleDateString('en-IN',{day:'numeric',month:'short',year:'numeric'});

    const fuelInfo = {
      petrol:{short:'Petrol',color:'var(--petrol-color,#ef4444)'},
      diesel:{short:'Diesel',color:'var(--diesel-color,#f97316)'},
      premium_petrol:{short:'Premium',color:'var(--premium-color,#8b5cf6)'},
    };

    // Day headers
    const dayHeaders = weekDays.map(date=>{
      const isToday=date===today, isSel=date===curAllocDate;
      const d=new Date(date);
      return `<th style="padding:8px 4px;text-align:center;min-width:100px;cursor:pointer;border-bottom:2px solid ${isSel?'var(--accent)':isToday?'var(--green)':'var(--border)'}"
        onclick="window.allocDate='${date}';renderPage()">
        <div style="font-size:10px;font-weight:700;color:${isToday?'var(--green)':isSel?'var(--accent-light)':'var(--text-3)'}">${d.toLocaleDateString('en-IN',{weekday:'short'}).toUpperCase()}</div>
        <div style="font-size:15px;font-weight:800;color:${isToday?'var(--green)':isSel?'var(--accent-light)':'var(--text-0)'}">${d.getDate()}</div>
      </th>`;
    }).join('');

    // Helper: get rostered/shift emps for a date
    function _dayEmps(date) {
      const rk = date+'_'+curAllocShift;
      const ids = (window._rosterData && window._rosterData[rk])||[];
      return ids.length>0
        ? D.employees.filter(e=>ids.includes(String(e.id)))
        : D.employees.filter(e=>(e.shift||'').split(',').map(s=>s.trim()).includes(curAllocShift));
    }

    // Build rows
    const rows = [];
    (D.pumps||[]).forEach(p=>{
      const nLabels = p.nozzleLabels||(p.nozzles===1?['A']:['A','B']);
      const pNozzleFuels = p.nozzleFuels||{};
      nLabels.forEach(n=>{
        const nKey=`${String(p.id)}_${n}`;
        const fi = fuelInfo[pNozzleFuels[n]||p.fuelType]||fuelInfo.petrol;
        const label=`<td style="padding:10px 12px;white-space:nowrap;border-right:1px solid var(--border);background:var(--bg-3);position:sticky;left:0;z-index:1">
          <div style="font-weight:800;font-size:12px;color:var(--text-0)">${p.name}</div>
          <div style="font-size:10px;margin-top:2px"><span style="color:${fi.color};font-weight:700">N${n}</span> <span style="color:var(--text-3)">${fi.short}</span></div>
        </td>`;
        const cells=weekDays.map(date=>{
          const dk=date+'_'+curAllocShift;
          const empId=(window.allocations||{})[dk]?.[nKey];
          const emp=empId?D.employees.find(e=>parseInt(e.id)===parseInt(empId)):null;
          const isToday=date===today,isSel=date===curAllocDate;
          const dayEmps=_dayEmps(date);
          const opts=dayEmps.map(e=>`<option value="${e.id}"${emp&&parseInt(e.id)===parseInt(emp.id)?' selected':''}>${sanitize(e.name)}</option>`).join('');
          const ini=emp?emp.name.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase():'';
          const clr=emp?(emp.color||'var(--accent)'):'';
          return `<td style="padding:5px;background:${isSel?'rgba(212,148,15,0.04)':isToday?'rgba(34,197,94,0.03)':'transparent'};border-right:1px solid var(--border-light);vertical-align:middle;min-width:110px">
            ${emp?`<div style="display:flex;align-items:center;gap:5px;background:rgba(34,197,94,0.08);border:1px solid rgba(34,197,94,0.25);border-radius:7px;padding:5px 7px;margin-bottom:4px">
              <span style="width:22px;height:22px;border-radius:6px;background:${clr};display:grid;place-items:center;color:#fff;font-size:9px;font-weight:800;flex-shrink:0">${ini}</span>
              <span style="font-size:11px;font-weight:700;color:var(--green);flex:1;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${sanitize(emp.name)}</span>
              <button style="background:none;border:none;color:var(--red);cursor:pointer;font-size:12px;padding:0" onclick="window.allocDate='${date}';removeAllocForDate(${p.id},'${n}','${date}')">✕</button>
            </div>`:''}
            <select onchange="window.allocDate='${date}';assignNozzleForDate(${p.id},'${n}','${date}',this.value);this.value=''"
              style="width:100%;font-size:11px;padding:5px 7px;border-radius:7px;background:var(--bg-1);border:1px solid var(--border);color:var(--text-2);cursor:pointer;outline:none">
              <option value="">${emp?'↺ Change':'＋ Assign'}</option>
              ${opts}
            </select>
          </td>`;
        }).join('');
        rows.push(`<tr style="border-bottom:1px solid var(--border-light)">${label}${cells}</tr>`);
      });
    });

    const board=`<div style="overflow-x:auto;border-radius:var(--radius);border:1px solid var(--border)">
      <table style="width:100%;border-collapse:collapse;min-width:700px">
        <thead><tr style="background:var(--bg-3)">
          <th style="padding:10px 12px;text-align:left;font-size:11px;color:var(--text-3);font-weight:700;border-right:1px solid var(--border);position:sticky;left:0;z-index:2;background:var(--bg-3)">PUMP / NOZZLE</th>
          ${dayHeaders}
        </tr></thead>
        <tbody>${rows.join('')}</tbody>
      </table>
    </div>`;

    return hdr+tabBar+`
      <div class="card mb-16">
        <div class="card-head">
          <h4>⛽ Pump &amp; Nozzle Allocation</h4>
          <div style="display:flex;gap:6px;flex-wrap:wrap">
            <button class="btn btn-ghost btn-sm" onclick="autoAssignAlloc()">⚡ Auto</button>
            <button class="btn btn-ghost btn-sm" onclick="clearShiftAllocConfirm()">🗑 Clear</button>
            <button class="btn btn-accent btn-sm" onclick="copyAllocModal()">📋 Copy</button>
          </div>
        </div>
        <div style="padding:12px 16px 8px">
          <div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:10px">${shiftTabs}</div>
          <div style="display:flex;align-items:center;gap:8px;margin-bottom:10px;flex-wrap:wrap">
            <button class="btn btn-ghost btn-sm" onclick="window.allocWeekAnchor='${pvW.toISOString().slice(0,10)}';renderPage()">&#8249; Prev</button>
            <span style="font-weight:700;font-size:12px;color:var(--text-1);flex:1;text-align:center">${weekLabel}</span>
            <button class="btn btn-ghost btn-sm" onclick="window.allocWeekAnchor='${nxW.toISOString().slice(0,10)}';renderPage()">Next &#8250;</button>
          </div>
          <div style="font-size:11px;color:var(--text-3);margin-bottom:8px">Assign employees to nozzles for <strong style="color:var(--accent-light)">${curAllocShift}</strong> shift</div>
        </div>
        <div style="padding:0 16px 16px">${board}</div>
      </div>`;
  }

  // ═══════════════════════════════════════════════════════════════
  // TAB: ROSTER
  // ═══════════════════════════════════════════════════════════════
  if (tab === 'roster') {
    if (!window._rosterData) window._rosterData = {};
    const offset = window._rosterWeekOffset || 0;
    const todayObj = new Date();
    const dow = todayObj.getDay()===0?6:todayObj.getDay()-1;
    const weekStart = new Date(todayObj); weekStart.setDate(todayObj.getDate()-dow+offset*7); weekStart.setHours(0,0,0,0);
    const thisMonday = new Date(todayObj); thisMonday.setDate(todayObj.getDate()-dow); thisMonday.setHours(0,0,0,0);
    const isPast = weekStart < thisMonday;
    const fmtDate = d=>d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0');
    const weekDays = Array.from({length:7},(_,i)=>{const d=new Date(weekStart);d.setDate(weekStart.getDate()+i);return d;});
    const shifts = D.shifts&&D.shifts.length?D.shifts:[{name:'Morning'},{name:'Afternoon'},{name:'Night'}];
    const shiftColors = ['rgba(212,148,15,0.12)','rgba(59,130,246,0.12)','rgba(139,92,246,0.12)','rgba(34,197,94,0.1)'];
    const shiftBorderColors = ['var(--accent)','#3b82f6','#8b5cf6','#22c55e'];

    const dayHeaders = weekDays.map(d=>{
      const isT=fmtDate(d)===today;
      return `<th style="text-align:center;padding:8px 4px;min-width:80px;${isT?'color:var(--accent-light);font-weight:800':''}">
        <div style="font-size:10px;font-weight:700;text-transform:uppercase">${d.toLocaleDateString('en-IN',{weekday:'short'})}</div>
        <div style="font-size:16px;font-weight:800;margin-top:1px${isT?';color:var(--accent)':''}">${d.getDate()}</div>
      </th>`;
    }).join('');

    const shiftRows = shifts.map((shift,si)=>{
      const cells=weekDays.map(d=>{
        const ds=fmtDate(d); const key=ds+'_'+shift.name;
        const assigned=(window._rosterData[key]||[]);
        const isT=ds===today;
        const assignedEmps=assigned.map(id=>D.employees.find(e=>String(e.id)===String(id))).filter(Boolean);
        const unassigned=D.employees.filter(e=>!assigned.includes(String(e.id)));
        const chips=assignedEmps.map(e=>{
          const ini=e.name.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase();
          return isPast
            ? `<div style="display:flex;align-items:center;gap:4px;background:var(--bg-1);border:1px solid var(--border-light);border-radius:6px;padding:3px 6px;margin-bottom:2px;opacity:0.72">
                <span style="width:18px;height:18px;border-radius:4px;background:${e.color||'var(--accent)'};display:grid;place-items:center;color:#fff;font-size:8px;font-weight:800">${ini}</span>
                <span style="font-size:10px;font-weight:700;color:var(--text-1)">${sanitize(e.name)}</span>
              </div>`
            : `<div style="display:flex;align-items:center;gap:4px;background:var(--bg-2);border:1px solid var(--border-light);border-radius:6px;padding:3px 6px;margin-bottom:2px;cursor:pointer"
                onclick="rosterUnassign('${ds}','${shift.name}',${e.id})">
                <span style="width:18px;height:18px;border-radius:4px;background:${e.color||'var(--accent)'};display:grid;place-items:center;color:#fff;font-size:8px;font-weight:800">${ini}</span>
                <span style="font-size:10px;font-weight:700;color:var(--text-0)">${sanitize(e.name)}</span>
                <span style="margin-left:auto;color:var(--red);font-size:10px;opacity:0.7">✕</span>
              </div>`;
        }).join('');
        const addDrop=isPast||!unassigned.length?'':
          `<select style="width:100%;background:var(--bg-1);border:1px dashed var(--border);border-radius:6px;padding:4px 5px;color:var(--text-3);font-size:10px;font-family:var(--font);cursor:pointer;margin-top:${assignedEmps.length?'4px':'0'}"
            onchange="if(this.value){rosterAssign('${ds}','${shift.name}',this.value);this.value=''}">
            <option value="">+ Assign</option>
            ${unassigned.map(e=>`<option value="${e.id}">${sanitize(e.name)}</option>`).join('')}
          </select>`;
        return `<td style="vertical-align:top;padding:5px;background:${isT?'rgba(212,148,15,0.04)':'transparent'};border-left:1px solid var(--border-light)">${chips}${addDrop}</td>`;
      }).join('');
      return `<tr>
        <td style="padding:8px 10px;white-space:nowrap;border-right:2px solid ${shiftBorderColors[si%4]};background:${shiftColors[si%4]}">
          <div style="font-size:11px;font-weight:800;color:var(--text-0)">${sanitize(shift.name)}</div>
          <div style="font-size:9px;color:var(--text-3)">${sanitize(shift.start||'')}–${sanitize(shift.end||'')}</div>
        </td>${cells}
      </tr>`;
    }).join('');

    const weekLabel=weekStart.toLocaleDateString('en-IN',{day:'numeric',month:'long',year:'numeric'});
    return hdr+tabBar+`
      <div style="display:flex;gap:8px;margin-bottom:12px;flex-wrap:wrap;align-items:center">
        <button class="btn btn-ghost btn-sm" onclick="rosterNavWeek(-1)">◀ Prev</button>
        <span style="font-size:12px;font-weight:700;color:var(--text-1);flex:1;text-align:center">Week of ${weekLabel}</span>
        <button class="btn btn-ghost btn-sm" onclick="rosterNavWeek(1)">Next ▶</button>
        ${!isPast?`<button class="btn btn-accent btn-sm" onclick="rosterSave()">💾 Save</button>`:''}
      </div>
      ${isPast?`<div style="padding:6px 10px;background:rgba(255,255,255,0.03);border:1px solid var(--border);border-radius:6px;font-size:11px;color:var(--text-3);margin-bottom:12px">🔒 Past week — read only</div>`:''}
      <div class="card" style="overflow-x:auto;padding:0">
        <table style="border-collapse:collapse;width:100%;min-width:600px">
          <thead style="background:var(--bg-1);border-bottom:2px solid var(--border)">
            <tr><th style="padding:8px 10px;text-align:left;min-width:80px;font-size:10px;text-transform:uppercase;color:var(--text-3)">Shift</th>${dayHeaders}</tr>
          </thead>
          <tbody>${shiftRows}</tbody>
        </table>
      </div>`;
  }

  // ═══════════════════════════════════════════════════════════════
  // TAB: ATTENDANCE
  // ═══════════════════════════════════════════════════════════════
  if (tab === 'attendance') {
    if (!window._attendanceData) window._attendanceData = {};
    if (!window._attDate) window._attDate = today;
    const attDate = window._attDate;
    const att = window._attendanceData;
    if (!att[attDate]) att[attDate] = {};
    const emps = (D.employees||[]).filter(e=>e.status!=='inactive');
    const statusOpts = ['present','absent','half-day','leave','holiday'];
    const statusColor = {present:'var(--green)',absent:'var(--red)','half-day':'var(--orange)',leave:'#8b5cf6',holiday:'#3b82f6'};
    const statusEmoji = {present:'✅',absent:'❌','half-day':'🌓',leave:'🏖️',holiday:'🎉'};
    const counts = statusOpts.reduce((a,s)=>{a[s]=0;return a;},{});
    emps.forEach(e=>{const s=att[attDate]?.[e.id]?.status||'absent';counts[s]=(counts[s]||0)+1;});

    const rows = emps.map(e=>{
      const rec=att[attDate]?.[e.id]||{};
      const status=rec.status||''; const note=rec.note||'';
      return `<tr>
        <td style="padding:10px 12px">
          <div style="font-weight:700;color:var(--text-0);font-size:13px">${sanitize(e.name)}</div>
          <div style="font-size:10px;color:var(--text-3)">${sanitize(e.role||'')} · ${sanitize((e.shift||'').split(',')[0]||'—')}</div>
        </td>
        <td style="padding:10px 12px">
          <select class="form-input" style="padding:6px 10px;font-size:12px;width:130px" onchange="attSetStatus(${e.id},'${attDate}',this.value)">
            <option value="">Mark status</option>
            ${statusOpts.map(s=>`<option value="${s}"${status===s?' selected':''} style="color:${statusColor[s]}">${statusEmoji[s]} ${s.charAt(0).toUpperCase()+s.slice(1)}</option>`).join('')}
          </select>
        </td>
        <td style="padding:10px 12px">
          ${status?`<span style="padding:3px 10px;border-radius:20px;font-size:11px;font-weight:700;background:${statusColor[status]}22;color:${statusColor[status]};border:1px solid ${statusColor[status]}44">${statusEmoji[status]} ${status.charAt(0).toUpperCase()+status.slice(1)}</span>`:'<span style="font-size:11px;color:var(--text-3)">Not marked</span>'}
        </td>
        <td style="padding:10px 12px">
          <input style="background:var(--bg-1);border:1px solid var(--border);border-radius:6px;padding:5px 8px;font-size:11px;color:var(--text-1);width:140px" placeholder="Note" value="${sanitize(note)}" oninput="attSetNote(${e.id},'${attDate}',this.value)" />
        </td>
      </tr>`;
    }).join('');

    return hdr+tabBar+`
      <div style="display:flex;gap:8px;margin-bottom:12px;flex-wrap:wrap;align-items:center">
        <input type="date" class="form-input" style="padding:6px 12px;font-size:13px;width:160px" value="${attDate}" onchange="window._attDate=this.value;renderPage()" />
        <button class="btn btn-accent btn-sm" onclick="attSave()">💾 Save</button>
        <button class="btn btn-ghost btn-sm" onclick="attMarkAllPresent('${attDate}')">✅ All Present</button>
      </div>
      <div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px">
        ${statusOpts.map(s=>`<div style="padding:5px 12px;border-radius:20px;font-size:11px;font-weight:700;background:${statusColor[s]}18;color:${statusColor[s]};border:1px solid ${statusColor[s]}33">${statusEmoji[s]} ${s.charAt(0).toUpperCase()+s.slice(1)}: ${counts[s]}</div>`).join('')}
      </div>
      <div class="card" style="padding:0;overflow:hidden">
        <div class="tbl-wrap"><table>
          <thead><tr><th>Employee</th><th>Mark Status</th><th>Status</th><th>Note</th></tr></thead>
          <tbody>${rows||'<tr><td colspan="4" style="text-align:center;color:var(--text-3);padding:24px">No employees</td></tr>'}</tbody>
        </table></div>
      </div>`;
  }

  // ═══════════════════════════════════════════════════════════════
  // TAB: DIRECTORY
  // ═══════════════════════════════════════════════════════════════
  const emps = D.employees||[];
  const pumps = D.pumps||[];
  const empAllocMap = {};
  Object.entries(window.allocations||{}).forEach(([dk,sa])=>{
    if (!dk.startsWith(today+'_')||typeof sa!=='object') return;
    const sn=dk.slice(today.length+1);
    Object.entries(sa).forEach(([key,empId])=>{
      if (!empId) return;
      const [pid,nozzle]=key.split('_');
      const pump=pumps.find(p=>String(p.id)===String(pid));
      if (!empAllocMap[empId]) empAllocMap[empId]=[];
      empAllocMap[empId].push({shift:sn,pumpName:pump?.name||('P'+pid),nozzle});
    });
  });
  const todayRosterIds=new Set();
  if (window._rosterData) Object.entries(window._rosterData).forEach(([rk,ids])=>{
    if (rk.startsWith(today+'_')&&Array.isArray(ids)) ids.forEach(id=>todayRosterIds.add(String(id)));
  });

  const rows = emps.map(e=>{
    const ini=e.name.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase();
    const myAllocs=empAllocMap[String(e.id)]||[];
    const allocPills=myAllocs.map(a=>`<span style="font-size:9px;font-weight:700;background:rgba(212,148,15,0.12);border:1px solid rgba(212,148,15,0.25);color:var(--accent-light);padding:2px 7px;border-radius:4px">${sanitize(a.pumpName)} N${a.nozzle}</span>`).join(' ');
    const rostered=todayRosterIds.has(String(e.id));
    return `<div style="display:flex;justify-content:space-between;align-items:center;padding:11px 0;border-bottom:1px solid var(--border-light)">
      <div style="display:flex;align-items:center;gap:10px">
        <div style="width:32px;height:32px;border-radius:8px;background:${e.color||'var(--accent)'};display:grid;place-items:center;color:#fff;font-size:10px;font-weight:800;flex-shrink:0">${ini}</div>
        <div>
          <div class="fw-700" style="font-size:13px;color:var(--text-0)">${sanitize(e.name)}</div>
          <div style="font-size:10px;color:var(--text-3)">${sanitize(e.role||'')} · ${sanitize(e.shift||'—')}</div>
          ${e.phone?`<div style="font-size:10px;color:var(--text-3)">📞 ${sanitize(e.phone)}</div>`:''}
        </div>
      </div>
      <div style="text-align:right">
        ${allocPills?`<div style="display:flex;gap:3px;flex-wrap:wrap;justify-content:flex-end;margin-bottom:4px">${allocPills}</div>`:''}
        ${rostered
          ?`<span style="font-size:9px;font-weight:700;background:rgba(34,197,94,0.1);border:1px solid rgba(34,197,94,0.25);color:var(--green);padding:2px 7px;border-radius:4px">✅ Rostered</span>`
          :`<span style="font-size:9px;color:var(--text-3)">Not rostered</span>`}
      </div>
    </div>`;
  }).join('')||`<div style="text-align:center;padding:20px;color:var(--text-3);font-size:12px">No employees found</div>`;

  return hdr+tabBar+`<div class="card"><div class="card-body" style="padding:0 16px">${rows}</div></div>`;
}
window.emp_renderStaffView = emp_renderStaffView;


